const dailyQuests = [
  { key: 'daily_hunt', name: '🎯 صياد اليوم', desc: 'اصطد 3 مخلوقات ظل', target: 3, reward: { gold: 200, xp: 50, essence: 10 } },
  { key: 'daily_explore', name: '🌍 مستكشف اليوم', desc: 'استكشف 5 مرات', target: 5, reward: { gold: 150, xp: 40, essence: 5 } },
  { key: 'daily_gold', name: '💰 كاسب اليوم', desc: 'اكسب 500 ذهب', target: 500, reward: { gold: 300, xp: 60, essence: 15 } },
  { key: 'daily_kill', name: '⚔️ قاتل اليوم', desc: 'اقتل 10 أعداء', target: 10, reward: { gold: 250, xp: 80, essence: 12 } },
  { key: 'daily_trade', name: '🤝 تاجر اليوم', desc: 'تداول مع لاعب', target: 1, reward: { gold: 400, xp: 100, essence: 20 } },
];

function getDailyQuestKey() {
  const today = new Date().toISOString().split('T')[0];
  // Use date to deterministically pick 3 quests
  const dayNum = today.split('-').reduce((a, b) => a + parseInt(b), 0);
  const shuffled = [...dailyQuests].sort((a, b) => {
    const ha = (dayNum * a.key.length + a.key.charCodeAt(0)) % 100;
    const hb = (dayNum * b.key.length + b.key.charCodeAt(0)) % 100;
    return ha - hb;
  });
  return shuffled.slice(0, 3);
}

function initDailyQuests(userId) {
  const today = new Date().toISOString().split('T')[0];
  const quests = getDailyQuestKey();

  for (const q of quests) {
    const existing = getQuery('SELECT * FROM quests WHERE user_id = ? AND quest_key = ?', [userId, `${q.key}_${today}`]);
    if (!existing) {
      runQuery('INSERT INTO quests (user_id, quest_key, progress, target) VALUES (?, ?, 0, ?)', [userId, `${q.key}_${today}`, q.target]);
    }
  }
}

function getQuests(userId) {
  const today = new Date().toISOString().split('T')[0];
  const quests = allQuery('SELECT * FROM quests WHERE user_id = ? AND quest_key LIKE ?', [userId, `%_${today}`]);
  // If no quests today, initialize
  if (quests.length === 0) {
    initDailyQuests(userId);
    return allQuery('SELECT * FROM quests WHERE user_id = ? AND quest_key LIKE ?', [userId, `%_${today}`]);
  }
  return quests;
}

function progressQuest(userId, key, amount = 1) {
  const today = new Date().toISOString().split('T')[0];
  const quest = getQuery('SELECT * FROM quests WHERE user_id = ? AND quest_key = ?', [userId, `${key}_${today}`]);
  if (!quest || quest.completed) return null;

  const newProgress = Math.min(quest.progress + amount, quest.target);
  const completed = newProgress >= quest.target ? 1 : 0;
  runQuery('UPDATE quests SET progress = ?, completed = ?, completed_at = CASE WHEN ? THEN CURRENT_TIMESTAMP ELSE NULL END WHERE id = ?', 
    [newProgress, completed, completed, quest.id]);

  if (completed) {
    const qDef = dailyQuests.find(q => q.key === key);
    if (qDef) {
      return qDef.reward;
    }
  }
  return null;
}

