// ====== FRIEND FUNCTIONS ======

function getFriends(userId, status = 'accepted') {
  const sent = allQuery('SELECT * FROM friends WHERE user_id = ? AND status = ?', [userId, status]);
  const received = allQuery('SELECT * FROM friends WHERE friend_id = ? AND status = ?', [userId, status]);
  const friendIds = [...sent.map(f => f.friend_id), ...received.map(f => f.user_id)];
  if (friendIds.length === 0) return [];
  const placeholders = friendIds.map(() => '?').join(',');
  return allQuery(`SELECT user_id, username, level FROM players WHERE user_id IN (${placeholders})`, friendIds);
}

function getFriendRequests(userId) {
  return allQuery(
    'SELECT f.*, p.username FROM friends f JOIN players p ON f.user_id = p.user_id WHERE f.friend_id = ? AND f.status = ?',
    [userId, 'pending']
  );
}

function sendFriendRequest(userId, friendId) {
  const existing = getQuery('SELECT * FROM friends WHERE user_id = ? AND friend_id = ?', [userId, friendId]);
  if (existing) return false;
  runQuery('INSERT INTO friends (user_id, friend_id, status) VALUES (?, ?, ?)', [userId, friendId, 'pending']);
  return true;
}

function acceptFriendRequest(userId, requesterId) {
  const req = getQuery('SELECT * FROM friends WHERE user_id = ? AND friend_id = ? AND status = ?', [requesterId, userId, 'pending']);
  if (!req) return false;
  runQuery('UPDATE friends SET status = ? WHERE user_id = ? AND friend_id = ?', ['accepted', requesterId, userId]);
  return true;
}

function removeFriend(userId, friendId) {
  runQuery('DELETE FROM friends WHERE (user_id = ? AND friend_id = ?) OR (user_id = ? AND friend_id = ?)', [userId, friendId, friendId, userId]);
}

