// ====== LOTTERY FUNCTIONS ======

function buyLotteryTicket(userId) {
  const maxTicket = getQuery('SELECT MAX(ticket_number) as max FROM lottery_tickets');
  const nextNum = (maxTicket?.max || 0) + 1;
  const result = runQuery('INSERT INTO lottery_tickets (user_id, ticket_number) VALUES (?, ?)', [userId, nextNum]);
  return result ? nextNum : null;
}

function getLotteryStats() {
  const total = getQuery('SELECT COUNT(*) as count FROM lottery_tickets');
  const lastWinner = getQuery('SELECT lt.*, p.username FROM lottery_tickets lt JOIN players p ON lt.user_id = p.user_id ORDER BY lt.id DESC LIMIT 1');
  return { total: total?.count || 0, lastWinner };
}

function drawLottery() {
  const tickets = allQuery('SELECT * FROM lottery_tickets ORDER BY RANDOM() LIMIT 1');
  if (tickets.length === 0) return null;
  const winner = tickets[0];
  runQuery('DELETE FROM lottery_tickets');
  return winner;
}

