}

function activateBooster(userId, type, multiplier = 1.5, duration = 30) {
  const expiresAt = new Date(Date.now() + duration * 60 * 1000).toISOString();
  return runQuery('INSERT INTO boosters (user_id, booster_type, multiplier, duration_minutes, expires_at) VALUES (?, ?, ?, ?, ?)',
    [userId, type, multiplier, duration, expiresAt]);
}

function getBoosterMultiplier(userId, type) {
  const boosters = getActiveBoosters(userId);
  let multiplier = 1.0;
  for (const b of boosters) {
    if (b.booster_type === type || b.booster_type === 'all') {
      multiplier = Math.max(multiplier, b.multiplier);
    }
  }
  return multiplier;
}

// ====== SERVER EVENT FUNCTIONS ======

function getActiveEvent() {
  return getQuery('SELECT * FROM server_events WHERE active = 1 AND ends_at > datetime("now")');
}

function startEvent(type, duration = 60, startedBy = 'system') {
  const endsAt = new Date(Date.now() + duration * 60 * 1000).toISOString();
  runQuery('UPDATE server_events SET active = 0 WHERE active = 1');
  return runQuery('INSERT INTO server_events (event_type, active, started_by, ends_at) VALUES (?, 1, ?, ?)', [type, startedBy, endsAt]);
}

function getEventMultiplier(type) {
  const event = getActiveEvent();
  if (!event) return 1.0;
  const multipliers = { double_xp: 2.0, gold_rush: 2.0, shadow_invasion: 1.5, luck_boost: 2.0 };
  if (event.event_type === 'double_xp' && type === 'xp') return 2.0;
  if (event.event_type === 'gold_rush' && type === 'gold') return 2.0;
  if (event.event_type === 'shadow_invasion') return 1.5;
  if (event.event_type === 'luck_boost' && type === 'luck') return 2.0;
  return 1.0;
}

// ====== LEADERBOARD ======

function getLeaderboard(type = 'level', limit = 10) {
  let query;
  switch (type) {
    case 'gold': query = 'SELECT user_id, username, gold FROM players ORDER BY gold DESC LIMIT ?'; break;
    case 'shadow_essence': query = 'SELECT user_id, username, shadow_essence FROM players ORDER BY shadow_essence DESC LIMIT ?'; break;
    case 'prestige': query = 'SELECT user_id, username, prestige, level FROM players ORDER BY prestige DESC, level DESC LIMIT ?'; break;
    case 'dungeon': query = 'SELECT d.*, p.username FROM dungeon_leaderboard d JOIN players p ON d.user_id = p.user_id ORDER BY d.best_floor DESC, d.total_kills DESC LIMIT ?'; break;
    case 'pvp': query = 'SELECT user_id, username, (SELECT COUNT(*) FROM shadows WHERE user_id = players.user_id AND wins > 0) as wins FROM players ORDER BY wins DESC LIMIT ?'; break;
    default: query = 'SELECT user_id, username, level, xp FROM players ORDER BY level DESC, xp DESC LIMIT ?'; break;
  }
  return allQuery(query, [limit]);
}

function getTopGuilds(limit = 10) {
  return allQuery(
    'SELECT g.*, COUNT(gm.user_id) as member_count FROM guilds g LEFT JOIN guild_members gm ON g.id = gm.guild_id GROUP BY g.id ORDER BY g.level DESC, g.xp DESC LIMIT ?',
    [limit]
  );
}

