    `${m.role === 'زعيم' ? '👑' : m.role === 'نائب' ? '⚜️' : '▪️'} **${m.username}** - ${m.role}`
  ).join('\n');

  return createBaseEmbed(`🏰 ${guild.name}`, guild.description || 'قبيلة من نسّاجي الظل', colors.secondary)
    .addFields(
      { name: '👑 الزعيم', value: `<@${guild.owner_id}>`, inline: true },
      { name: '📊 المستوى', value: `${guild.level}`, inline: true },
      { name: '👥 الأعضاء', value: `${members.length}`, inline: true },
      { name: '📋 الأعضاء:', value: memberList || 'لا يوجد أعضاء', inline: false }
    );
}

function createBattleEmbed(player, enemy, playerHp, enemyHp, log) {
  const embed = createBaseEmbed('⚔️ معركة الظل', `**${player.username}** ⚔️ **${enemy.name}**`, colors.danger)
    .addFields(
      { name: `❤️ ${player.username}`, value: `${playerHp}/${player.health}`, inline: true },
      { name: `❤️ ${enemy.name}`, value: `${enemyHp}/${enemy.hp}`, inline: true },
      { name: '📜 سير المعركة', value: `\`\`\`${log.slice(0, 500)}\`\`\``, inline: false }
    );

  return embed;
}

function createActionRow(...buttons) {
  return new ActionRowBuilder().addComponents(buttons);
}

function createButton(customId, label, style = ButtonStyle.Primary, emoji = '', disabled = false) {
  return new ButtonBuilder()
    .setCustomId(customId)
    .setLabel(label)
    .setStyle(style)
    .setEmoji(emoji)
