}

function createLeaderboardEmbed(players, type = 'level') {
  const titles = { 
    level: '📊 لوحة الشرف - المستوى', 
    gold: '💰 لوحة الشرف - الذهب', 
    shadow_essence: '💎 لوحة الشرف - جوهر الظل',
    prestige: '🌀 لوحة الشرف - التمرير',
    dungeon: '🚪 لوحة الشرف - الزنزانات',
    pvp: '⚔️ لوحة الشرف - القتال'
  };
  const title = titles[type] || titles.level;

  const medals = ['🥇', '🥈', '🥉'];
  const list = players.map((p, i) => {
    const medal = medals[i] || `${i + 1}.`;
    let stat = '';
    if (type === 'level') stat = `المستوى ${p.level} | XP: ${p.xp}`;
    else if (type === 'gold') stat = `${p.gold.toLocaleString()} 💰`;
    else if (type === 'shadow_essence') stat = `${p.shadow_essence.toLocaleString()} 💎`;
    else if (type === 'prestige') stat = `التمرير ${p.prestige} | المستوى ${p.level}`;
    else if (type === 'dungeon') stat = `الطابق ${p.best_floor} | 💀 ${p.total_kills} قتلة`;
    else if (type === 'pvp') stat = `${p.wins || 0} انتصارات`;
    return `${medal} **${p.username}** — ${stat}`;
  }).join('\n');

  return createBaseEmbed(title, list, colors.gold);
}

