// Element effectiveness
const elementChart = {
  'ناري': { strong: ['هوائي'], weak: ['مائي'] },
  'مائي': { strong: ['ناري'], weak: ['ترابي'] },
  'ترابي': { strong: ['مائي'], weak: ['هوائي'] },
  'هوائي': { strong: ['ترابي'], weak: ['ناري'] },
  'ظلامي': { strong: ['نوراني'], weak: ['ناري'] },
  'نوراني': { strong: ['ظلامي'], weak: ['ظلامي'] }
};

function getElementMultiplier(attackType, defenseType) {
  if (elementChart[attackType]?.strong.includes(defenseType)) return 1.5;
  if (elementChart[attackType]?.weak.includes(defenseType)) return 0.75;
  return 1.0;
}

function generateShadowName() {
  return randomPick(shadowNames);
}

function generateShadowType() {
  return randomPick(shadowTypes);
}

function generateRarity() {
  // Increase luck-based rarity
  return weightedRandom(rarities, rarityWeights);
}

function generateShadowWithLuck(luck = 5) {
  const adjustedWeights = rarityWeights.map((w, i) => {
    if (i === 0) return Math.max(10, w - luck * 2);
    if (i === 1) return w + luck;
    if (i === 2) return w + luck * 0.5;
    return w + luck * 0.3;
  });
  const total = adjustedWeights.reduce((a, b) => a + b, 0);
  const normalized = adjustedWeights.map(w => w / total * 100);
  return weightedRandom(rarities, normalized);
}

