const { SlashCommandBuilder } = require('discord.js');
const { getPlayer, updatePlayer, getQuery, runQuery } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const config = require('../../config.json');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('daily')
    .setDescription('🎁 المكافأة اليومية - استلم ذهب وجواهر كل يوم!'),

  async execute(interaction) {
    const player = getPlayer(interaction.user.id, interaction.user.username);
    const now = new Date();
    const today = now.toISOString().split('T')[0];

    // Check if already claimed today
    const existing = getQuery('SELECT * FROM daily_log WHERE user_id = ? AND date = ?', [interaction.user.id, today]);

    if (existing) {
      const embed = createBaseEmbed('🎁 المكافأة اليومية', 'لقد استلمت مكافأتك اليوم بالفعل!\nتعال غداً للحصول على مكافأة جديدة.', 0xff4444);
      return interaction.reply({ embeds: [embed], ephemeral: true });
    }

    // Calculate streak
    const yesterday = new Date(now);
    yesterday.setDate(yesterday.getDate() - 1);
    const yesterdayStr = yesterday.toISOString().split('T')[0];

    const yesterdayLog = getQuery('SELECT * FROM daily_log WHERE user_id = ? AND date = ?', [interaction.user.id, yesterdayStr]);
    const streak = yesterdayLog ? (player.daily_streak || 0) + 1 : 1;

    // Calculate rewards
    let goldReward = config.economy.dailyAmount;
    let essenceReward = 5;
    let xpReward = 20;

    // Streak bonus
    if (streak > 1) {
      goldReward += (streak - 1) * config.economy.dailyStreakBonus;
      essenceReward += Math.floor((streak - 1) * 2);
      xpReward += (streak - 1) * 5;
    }

    // Cap rewards
    goldReward = Math.min(goldReward, 2000);
    essenceReward = Math.min(essenceReward, 100);
    xpReward = Math.min(xpReward, 200);

    // Special bonus at streak milestones
    let bonusText = '';
    if (streak % 7 === 0) {
      goldReward += 500;
      essenceReward += 20;
      bonusText = '\n✨ **مكافأة أسبوعية!** +500 ذهب إضافية!';
    }
    if (streak % 30 === 0) {
      goldReward += 2000;
      essenceReward += 50;
      bonusText += '\n👑 **مكافأة شهرية!** +2000 ذهب إضافية!';
    }

    // Update player
    updatePlayer(interaction.user.id, {
      gold: player.gold + goldReward,
      shadow_essence: (player.shadow_essence || 0) + essenceReward,
      xp: player.xp + xpReward,
      daily_streak: streak
    });

    // Log daily
    runQuery('INSERT INTO daily_log (user_id, date, streak, amount) VALUES (?, ?, ?, ?)', [interaction.user.id, today, streak, goldReward]);

    const embed = createBaseEmbed('🎁 المكافأة اليومية', 
      `مرحباً ${interaction.user.username}! استلم مكافأتك اليومية.\n\n` +
      `🔥 **السلسلة:** ${streak} يوم\n` +
      `💰 **ذهـب:** +${goldReward}\n` +
      `💎 **جوهر الظل:** +${essenceReward}\n` +
      `📊 **خبرة:** +${xpReward}` +
      bonusText +
      `\n\n📅 عد غداً لمكافأة أكبر!`,
      0xffd700
    );

    await interaction.reply({ embeds: [embed] });
  }
};

