const { SlashCommandBuilder } = require('discord.js');
const { getPlayer, updatePlayer, addItem } = require('../../database/db');
const { shopItems } = require('../../utils/helpers');
const { createBaseEmbed } = require('../../utils/embeds');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('buy')
    .setDescription('🛒 شراء منتج من متجر الظل')
    .addStringOption(option =>
      option.setName('product')
        .setDescription('اسم المنتج أو معرفه')
        .setRequired(true)
        .setAutocomplete(true)
    )
    .addIntegerOption(option =>
      option.setName('quantity')
        .setDescription('الكمية (الافتراضي: 1)')
        .setRequired(false)
        .setMinValue(1)
        .setMaxValue(99)
    ),

  async execute(interaction) {
    const productName = interaction.options.getString('product');
    const quantity = interaction.options.getInteger('quantity') || 1;

    // Find the product
    const product = shopItems.find(i => 
      i.name === productName || i.id === productName || productName.includes(i.name)
    );

    if (!product) {
      const embed = createBaseEmbed('❌ منتج غير موجود', 'لم أجد هذا المنتج. استخدم `/shop` لعرض المنتجات المتاحة.', 0xff4444);
      return interaction.reply({ embeds: [embed], ephemeral: true });
    }

    const player = getPlayer(interaction.user.id, interaction.user.username);
    const totalCost = product.price * quantity;

    if (player.gold < totalCost) {
      const embed = createBaseEmbed('❌ رصيد غير كافٍ', 
        `تحتاج ${totalCost.toLocaleString()} ذهب لشراء ${quantity}x ${product.name}.\n` +
        `لديك فقط ${player.gold.toLocaleString()} ذهب.`, 0xff4444);
      return interaction.reply({ embeds: [embed], ephemeral: true });
    }

    // Process purchase
    updatePlayer(interaction.user.id, { gold: player.gold - totalCost });

    const statsStr = JSON.stringify(product.stats || {});
    addItem(interaction.user.id, product.type, product.name, product.rarity, quantity, statsStr);

    const embed = createBaseEmbed('✅ تم الشراء بنجاح!', 
      `**${quantity}x ${product.name}**\n` +
      `⭐ الندرة: ${product.rarity}\n` +
      `💰 التكلفة: ${totalCost.toLocaleString()} ذهب\n` +
      `📦 تمت إضافة المشتريات إلى مخزونك.`,
      0x00ff88
    );

    await interaction.reply({ embeds: [embed] });
  }
};

