        `تحتاج 15 طاقة للصيد. طاقتك الحالية: ${player.energy}/${player.max_energy}`,
        0xff4444
      );
      return interaction.reply({ embeds: [embed], ephemeral: true });
    }

    // Deduct energy
    updatePlayer(interaction.user.id, { energy: player.energy - 15 });

    // Find enemy
    const enemy = getRandomEnemy(player.level);

    // Apply some variance to enemy stats
    const enemyInstance = {
      ...enemy,
      hp: enemy.hp + randomInt(-5, 10),
      attack: enemy.attack + randomInt(-2, 3),
      defense: enemy.defense + randomInt(-1, 2)
    };

    const embed = createBaseEmbed('⚔️ صيد الظل', 
      `**${interaction.user.username}** يبحث في البرية عن مخلوقات الظل...\n\n` +
      `👾 **ظهر ${enemyInstance.name}!**\n\n` +
      `❤️ HP: ${enemyInstance.hp}\n` +
      `⚔️ هجوم: ${enemyInstance.attack}\n` +
      `🛡️ دفاع: ${enemyInstance.defense}\n\n` +
      `📊 مكافأة: ${enemyInstance.xpReward} XP | ${enemyInstance.goldReward} 🪙`,
      0xff4444
    );

    const row = new ActionRowBuilder()
      .addComponents(
        new ButtonBuilder()
          .setCustomId(`hunt_attack:${encodeURIComponent(JSON.stringify(enemyInstance))}:${player.health}:${enemyInstance.hp}`)
          .setLabel('⚔️ هجوم')
          .setStyle(ButtonStyle.Danger),
        new ButtonBuilder()
          .setCustomId('hunt_flee')
          .setLabel('🏃 فرار')
          .setStyle(ButtonStyle.Secondary)
      );

    await interaction.reply({ embeds: [embed], components: [row] });
  }
};

const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer } = require('../../database/db');
