const { createBaseEmbed } = require('../../utils/embeds');

const activeDuels = new Map();

module.exports = {
  data: new SlashCommandBuilder()
    .setName('duel')
    .setDescription('🤺 مبارزة لاعب آخر في مبارزة شرف')
    .addUserOption(option =>
      option.setName('opponent')
        .setDescription('اللاعب الذي تريد مبارزته')
        .setRequired(true)
    )
    .addIntegerOption(option =>
      option.setName('bet')
        .setDescription('مبلغ الرهان (ذهب)')
        .setRequired(false)
        .setMinValue(10)
    ),

  async execute(interaction) {
    const opponent = interaction.options.getUser('opponent');
    const bet = interaction.options.getInteger('bet') || 0;

    if (opponent.id === interaction.user.id) {
      return interaction.reply({ content: '❌ لا يمكنك مبارزة نفسك!', ephemeral: true });
    }

    if (opponent.bot) {
      return interaction.reply({ content: '❌ لا يمكنك مبارزة البوتات!', ephemeral: true });
    }

    const challenger = getPlayer(interaction.user.id, interaction.user.username);
    const defender = getPlayer(opponent.id, opponent.username);

    if (bet > 0) {
      if (challenger.gold < bet) {
        return interaction.reply({ content: `❌ ليس لديك ${bet} ذهب للمراهنة!`, ephemeral: true });
      }
      if (defender.gold < bet) {
        return interaction.reply({ content: `❌ ${opponent.username} ليس لديه ${bet} ذهب للمراهنة!`, ephemeral: true });
      }
    }

    // Check for existing duel
    if (activeDuels.has(interaction.user.id) || activeDuels.has(opponent.id)) {
      return interaction.reply({ content: '❌ أحد اللاعبين مشغول بالفعل في مبارزة!', ephemeral: true });
    }

    const duelId = `${interaction.user.id}-${opponent.id}-${Date.now()}`;
    activeDuels.set(interaction.user.id, duelId);

    const embed = createBaseEmbed('🤺 طلب مبارزة', 
      `**${interaction.user.username}** يتحدى **${opponent.username}** في مبارزة شرف!\n\n` +
      `⚔️ **${interaction.user.username}** - المستوى ${challenger.level}\n` +
      `⚔️ **${opponent.username}** - المستوى ${defender.level}\n` +
      (bet > 0 ? `💰 **الرهان:** ${bet} ذهب\n` : '') +
      `\nعلى ${opponent} الرد خلال 30 ثانية!`,
      0xff6600
    );

    const row = new ActionRowBuilder()
      .addComponents(
        new ButtonBuilder()
          .setCustomId(`duel_accept:${interaction.user.id}:${bet}`)
          .setLabel('✅ قبول')
          .setStyle(ButtonStyle.Success),
        new ButtonBuilder()
          .setCustomId(`duel_decline:${interaction.user.id}`)
          .setLabel('❌ رفض')
          .setStyle(ButtonStyle.Danger)
      );

    await interaction.reply({ embeds: [embed], components: [row] });

    // Clean up after timeout
    setTimeout(() => {
      activeDuels.delete(interaction.user.id);
      activeDuels.delete(opponent.id);
    }, 30000);
  }
};

