module.exports = {
  data: new SlashCommandBuilder()
    .setName('inventory')
    .setDescription('🎒 عرض محتويات حقيبة الظل الخاصة بك'),

  async execute(interaction) {
    const inventory = getInventory(interaction.user.id);

    if (inventory.length === 0) {
      const embed = createBaseEmbed('🎒 الحقيبة فارغة', 
        'لم تجمع أي عناصر بعد!\n\nاستخدم `/explore` للاستكشاف أو `/hunt` للصيد أو `/shop` للشراء.',
        0x888888
      );
      return interaction.reply({ embeds: [embed] });
    }

    // Group by category
    const categories = {};
    const categoryEmojis = { 'weapon': '⚔️', 'armor': '🛡️', 'potion': '🧪', 'material': '💎', 'essence': '🔮' };
    const categoryNames = { 'weapon': 'أسلحة', 'armor': 'دروع', 'potion': 'جرعات', 'material': 'مواد', 'essence': 'جواهر' };

    for (const item of inventory) {
      const cat = item.item_type;
      if (!categories[cat]) categories[cat] = [];
      categories[cat].push(item);
    }

    const pages = [];
    let currentPage = 0;

    let description = '';
    for (const [cat, items] of Object.entries(categories)) {
      const emoji = categoryEmojis[cat] || '📦';
      const name = categoryNames[cat] || cat;
      description += `\n**${emoji} ${name}**\n`;
      description += items.map(item => {
        const rarityEmojis = { 'شائع': '⬜', 'نادر': '🟦', 'أسطوري': '🟨', 'خرافي': '🟪' };
        return `${rarityEmojis[item.item_rarity] || '⬜'} **${item.item_name}** ×${item.quantity} ${item.equipped ? '✅ مجهز' : ''}`;
      }).join('\n');
    }

    const embed = createBaseEmbed(`🎒 حقيبة الظل - ${interaction.user.username}`, 
      description || 'لا يوجد عناصر',
      0x00aaff
    );
    embed.setFooter({ text: `📦 ${inventory.length} عنصر • ${Object.keys(categories).length} فئة` });

    await interaction.reply({ embeds: [embed] });
  }
};

