module.exports = {
  data: new SlashCommandBuilder()
    .setName('craft')
    .setDescription('🔨 صياغة عناصر جديدة باستخدام المواد التي جمعتها'),

  async execute(interaction) {
    const categories = Object.keys(recipes);

    const select = new StringSelectMenuBuilder()
      .setCustomId('craft_select')
      .setPlaceholder('🔨 اختر فئة للصياغة...')
      .addOptions(
        categories.map(cat => 
          new StringSelectMenuOptionBuilder()
            .setLabel(cat === 'weapon' ? 'أسلحة' : cat === 'potion' ? 'جرعات' : 'مواد')
            .setValue(cat)
            .setDescription(`صياغة ${cat === 'weapon' ? 'أسلحة' : cat === 'potion' ? 'جرعات' : 'مواد'} متطورة`)
            .setEmoji(cat === 'weapon' ? '⚔️' : cat === 'potion' ? '🧪' : '💎')
        )
      );

    const row = new ActionRowBuilder().addComponents(select);

    const embed = createBaseEmbed('🔨 ورشة الصياغة', 
      'اختر فئة لترى الوصفات المتاحة للصياغة.\n\n' +
      '**المواد المتوفرة لديك ستظهر تلقائياً.**',
      0xff8800
    );

    await interaction.reply({ embeds: [embed], components: [row] });

    // Handle selection
    const filter = i => i.customId === 'craft_select' && i.user.id === interaction.user.id;
    try {
      const selection = await interaction.channel.awaitMessageComponent({ filter, time: 30000 });
      const category = selection.values[0];
      const categoryRecipes = recipes[category];

      const inventory = getInventory(interaction.user.id);
      const inventoryMap = {};
      for (const item of inventory) {
        inventoryMap[item.item_name] = item;
      }

      let description = '';
      for (const recipe of categoryRecipes) {
        const canCraft = recipe.required.every(req => {
          const inv = inventoryMap[req.item];
          return inv && inv.quantity >= req.qty;
        });

        description += `${canCraft ? '✅' : '❌'} **${recipe.result.name}** (${recipe.result.rarity})\n`;
        description += `   المواد: ${recipe.required.map(r => `${r.item} ×${r.qty} ${(inventoryMap[r.item]?.quantity || 0) >= r.qty ? '✅' : `❌(${inventoryMap[r.item]?.quantity || 0})`}`).join(', ')}\n`;
        description += `   النتيجة: ${recipe.result.name} ⭐${recipe.result.rarity}\n\n`;
      }

      const craftEmbed = createBaseEmbed(`🔨 ${category === 'weapon' ? 'أسلحة' : category === 'potion' ? 'جرعات' : 'مواد'}`, description, 0xff8800);
      craftEmbed.setFooter({ text: 'استخدم /craft [اسم الوصفة] للصياغة' });

      await selection.update({ embeds: [craftEmbed], components: [] });
    } catch (e) {
      if (e.code !== 'INTERACTION_COLLECTOR_ERROR') {
        // Ignore timeout
      }
    }
  }
};

const { SlashCommandBuilder } = require('discord.js');
const { getPlayer, updatePlayer, getInventory, addItem, removeItem } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { randomInt, chance } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('forge')
    .setDescription('⚒️ تطوير أسلحتك ودروعك باستخدام جواهر الظل')
    .addStringOption(option =>
      option.setName('item')
        .setDescription('اسم العنصر الذي تريد تطويره')
        .setRequired(true)
        .setAutocomplete(true)
    ),

  async execute(interaction) {
    const itemName = interaction.options.getString('item');
    const inventory = getInventory(interaction.user.id);
    const player = getPlayer(interaction.user.id, interaction.user.username);

    // Find the item
    const item = inventory.find(i => i.item_name === itemName);
    if (!item) {
      return interaction.reply({ content: '❌ لم أجد هذا العنصر في مخزونك!', ephemeral: true });
    }

    // Only weapons and armor can be forged
    if (item.item_type !== 'weapon' && item.item_type !== 'armor') {
      return interaction.reply({ content: '❌ يمكن تطوير الأسلحة والدروع فقط!', ephemeral: true });
    }

    const essenceCost = item.item_rarity === 'شائع' ? 20 : item.item_rarity === 'نادر' ? 50 : item.item_rarity === 'أسطوري' ? 150 : 500;
    const goldCost = item.item_rarity === 'شائع' ? 200 : item.item_rarity === 'نادر' ? 500 : item.item_rarity === 'أسطوري' ? 2000 : 10000;

    if ((player.shadow_essence || 0) < essenceCost) {
      return interaction.reply({ content: `❌ تحتاج ${essenceCost} جوهر ظل للتطوير! لديك ${player.shadow_essence || 0}.`, ephemeral: true });
    }
    if (player.gold < goldCost) {
      return interaction.reply({ content: `❌ تحتاج ${goldCost} ذهب للتطوير! لديك ${player.gold}.`, ephemeral: true });
    }

    // Calculate success chance
    const successChance = item.item_rarity === 'شائع' ? 80 : item.item_rarity === 'نادر' ? 60 : item.item_rarity === 'أسطوري' ? 35 : 15;

    const embed = createBaseEmbed('⚒️ تطوير العنصر',
      `**${item.item_name}**\n\n` +
      `⭐ الندرة الحالية: ${item.item_rarity}\n` +
      `💎 تكلفة الجوهر: ${essenceCost}\n` +
      `💰 تكلفة الذهب: ${goldCost}\n` +
      `📊 فرصة النجاح: ${successChance}%\n\n` +
      `هل تريد تطوير هذا العنصر؟`,
