const { SlashCommandBuilder } = require('discord.js');
const { getPlayer, updatePlayer, getPlayerGuild, getGuild, getGuildByName, getGuildMembers, runQuery, allQuery, getQuery } = require('../../database/db');
const { createBaseEmbed, createGuildEmbed } = require('../../utils/embeds');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('guild')
    .setDescription('🏰 نظام القبائل - أنشئ أو انضم إلى قبيلة')
    .addSubcommand(sub =>
      sub.setName('create')
        .setDescription('إنشاء قبيلة جديدة')
        .addStringOption(option =>
          option.setName('name')
            .setDescription('اسم القبيلة')
            .setRequired(true)
            .setMinLength(3)
            .setMaxLength(30)
        )
        .addStringOption(option =>
          option.setName('description')
            .setDescription('وصف القبيلة')
            .setRequired(false)
            .setMaxLength(200)
        )
    )
    .addSubcommand(sub =>
      sub.setName('join')
        .setDescription('الانضمام إلى قبيلة')
        .addStringOption(option =>
          option.setName('guild_name')
            .setDescription('اسم القبيلة')
            .setRequired(true)
            .setAutocomplete(true)
        )
    )
    .addSubcommand(sub =>
      sub.setName('info')
        .setDescription('عرض معلومات قبيلتك')
    )
    .addSubcommand(sub =>
      sub.setName('list')
        .setDescription('عرض قائمة القبائل')
    )
    .addSubcommand(sub =>
      sub.setName('leave')
        .setDescription('مغادرة القبيلة الحالية')
    ),

  async execute(interaction) {
    const subcommand = interaction.options.getSubcommand();

    switch (subcommand) {
      case 'create':
        return handleCreate(interaction);
      case 'join':
        return handleJoin(interaction);
      case 'info':
        return handleInfo(interaction);
      case 'list':
        return handleList(interaction);
      case 'leave':
        return handleLeave(interaction);
    }
  }
};

async function handleCreate(interaction) {
  const name = interaction.options.getString('name');
  const description = interaction.options.getString('description') || 'قبيلة من نسّاجي الظل';

  const player = getPlayer(interaction.user.id, interaction.user.username);

  const existingGuild = getPlayerGuild(interaction.user.id);
  if (existingGuild) {
    return interaction.reply({ content: `❌ أنت بالفعل في قبيلة **${existingGuild.name}**! اتركها أولاً باستخدام \`/guild leave\`.`, ephemeral: true });
  }

  const nameExists = getGuildByName(name);
  if (nameExists) {
    return interaction.reply({ content: '❌ هذا الاسم مستخدم بالفعل!', ephemeral: true });
  }

  if (player.gold < 5000) {
    return interaction.reply({ content: '❌ تحتاج 5000 ذهب لإنشاء قبيلة!', ephemeral: true });
  }

  updatePlayer(interaction.user.id, { gold: player.gold - 5000 });

  const result = runQuery('INSERT INTO guilds (name, owner_id, description) VALUES (?, ?, ?)', [name, interaction.user.id, description]);
  runQuery('INSERT INTO guild_members (guild_id, user_id, role) VALUES (?, ?, ?)', [result.lastInsertRowid, interaction.user.id, 'زعيم']);

  const embed = createBaseEmbed('🏰 تم إنشاء القبيلة!', 
    `تم إنشاء قبيلة **${name}** بنجاح!\n\n` +
    `👑 الزعيم: ${interaction.user.username}\n` +
    `📝 الوصف: ${description}\n` +
    `💰 التكلفة: 5000 ذهب\n\n` +
    `استخدم \`/guild info\` لعرض معلومات القبيلة.`,
    0x6a0dad
  );

  await interaction.reply({ embeds: [embed] });
}

async function handleJoin(interaction) {
  const guildName = interaction.options.getString('guild_name');
  const guild = getGuildByName(guildName);

  if (!guild) {
    return interaction.reply({ content: '❌ لا توجد قبيلة بهذا الاسم!', ephemeral: true });
  }

  const existingGuild = getPlayerGuild(interaction.user.id);
  if (existingGuild) {
    return interaction.reply({ content: `❌ أنت بالفعل في قبيلة **${existingGuild.name}**! اتركها أولاً.`, ephemeral: true });
  }

  const member = getQuery('SELECT * FROM guild_members WHERE guild_id = ? AND user_id = ?', [guild.id, interaction.user.id]);
  if (member) {
    return interaction.reply({ content: '❌ أنت بالفعل عضو في هذه القبيلة!', ephemeral: true });
  }

  runQuery('INSERT INTO guild_members (guild_id, user_id, role) VALUES (?, ?, ?)', [guild.id, interaction.user.id, 'عضو']);

  const embed = createBaseEmbed('✅ انضممت إلى القبيلة!',
    `مرحباً بك في **${guild.name}**!\n\n` +
    `👑 الزعيم: <@${guild.owner_id}>\n` +
    `📊 مستوى القبيلة: ${guild.level}`,
    0x00ff88
  );

  await interaction.reply({ embeds: [embed] });
}

async function handleInfo(interaction) {
  const guild = getPlayerGuild(interaction.user.id);

  if (!guild) {
    return interaction.reply({ content: '❌ أنت لست في أي قبيلة! استخدم `/guild create` أو `/guild join`.', ephemeral: true });
  }

  const members = getGuildMembers(guild.id);
  const embed = createGuildEmbed(guild, members);
  await interaction.reply({ embeds: [embed] });
}

async function handleList(interaction) {
  const guilds = allQuery(
    'SELECT g.*, COUNT(gm.user_id) as member_count FROM guilds g LEFT JOIN guild_members gm ON g.id = gm.guild_id GROUP BY g.id ORDER BY g.level DESC, g.xp DESC LIMIT 20'
  );

  if (guilds.length === 0) {
    return interaction.reply({ content: '❌ لا توجد قبائل مسجلة بعد! كن أنت الأول باستخدام `/guild create`.', ephemeral: true });
  }

  const list = guilds.map((g, i) => 
    `**${i + 1}.** ${g.name} (المستوى ${g.level})\n` +
    `   👥 ${g.member_count} أعضاء | 👑 <@${g.owner_id}>`
  ).join('\n\n');

  const embed = createBaseEmbed('🏰 قائمة القبائل', list, 0x6a0dad);
  await interaction.reply({ embeds: [embed] });
}

async function handleLeave(interaction) {
  const guild = getPlayerGuild(interaction.user.id);

  if (!guild) {
    return interaction.reply({ content: '❌ أنت لست في أي قبيلة!', ephemeral: true });
  }

  if (guild.owner_id === interaction.user.id) {
    return interaction.reply({ content: '❌ لا يمكنك مغادرة القبيلة وأنت الزعيم! قم بنقل الزعامة أولاً أو احذف القبيلة.', ephemeral: true });
  }

  runQuery('DELETE FROM guild_members WHERE guild_id = ? AND user_id = ?', [guild.id, interaction.user.id]);

  const embed = createBaseEmbed('👋 غادرت القبيلة', `لقد غادرت قبيلة **${guild.name}** بنجاح.`, 0x888888);
  await interaction.reply({ embeds: [embed] });
}

