const { SlashCommandBuilder, EmbedBuilder } = require('discord.js');
const { getPlayer, getAchievements, checkAchievements } = require('../../database/db');
const { achievementList } = require('../../utils/helpers');
const { createBaseEmbed } = require('../../utils/embeds');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('achievements')
    .setDescription('🏆 عرض إنجازاتك في ممالك الظل'),

  async execute(interaction) {
    const player = getPlayer(interaction.user.id, interaction.user.username);
    const newOnes = checkAchievements(interaction.user.id);
    const unlocked = getAchievements(interaction.user.id);
    const unlockedKeys = new Set(unlocked.map(a => a.achievement_key));

    const total = achievementList.length;
    const earned = unlocked.length;

    let description = `**📊 الإنجازات: ${earned}/${total}**\n\n`;

    const categories = [
      { emoji: '⭐', range: [0, 5], name: 'المستوى' },
      { emoji: '💰', range: [6, 8], name: 'الاقتصاد' },
      { emoji: '💎', range: [9, 10], name: 'الجواهر' },
      { emoji: '👾', range: [11, 15], name: 'المخلوقات' },
      { emoji: '🔥', range: [16, 17], name: 'السلسلة' },
      { emoji: '🏰', range: [18, 19], name: 'القبائل' },
      { emoji: '🔮', range: [20, 28], name: 'متفرقات' },
    ];

    for (const cat of categories) {
      const catAchievements = achievementList.slice(cat.range[0], cat.range[1] + 1);
      description += `**${cat.emoji} ${cat.name}**\n`;
      for (const a of catAchievements) {
        const isUnlocked = unlockedKeys.has(a.key);
        description += `${isUnlocked ? '✅' : '❌'} **${a.name}** - ${a.desc}\n`;
      }
      description += '\n';
    }

    const embed = createBaseEmbed(`🏆 إنجازات ${interaction.user.username}`, description, 0xffd700);

    if (newOnes.length > 0) {
      const newDesc = newOnes.map(a => `🎉 **${a.name}** - ${a.desc}`).join('\n');
      embed.addFields({ name: '🆕 إنجازات جديدة!', value: newDesc, inline: false });
    }

    await interaction.reply({ embeds: [embed] });
  }
};

