const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer, getActiveWorldBoss, spawnWorldBoss, runQuery, getQuery, allQuery, checkAchievements } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { randomInt, chance, calculateDamage, progressBar } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('boss')
    .setDescription('🐉 قتال البوس العالمي - تعاون مع الجميع لهزيمته'),

  async execute(interaction) {
    let boss = getActiveWorldBoss();

    // If no boss active, spawn one
    if (!boss) {
      boss = spawnWorldBoss();
      if (!boss) {
        return interaction.reply({ content: '❌ حدث خطأ في استدعاء البوس!', ephemeral: true });
      }

      // Announce
      const announceEmbed = createBaseEmbed('🐉 **بوس عالمي جديد!**',
        `**${boss.name}** ظهر في عالم الظل!\n\n` +
        `❤️ HP: ${boss.hp.toLocaleString()}\n` +
        `⚔️ هجوم: ${boss.attack}\n` +
        `🛡️ دفاع: ${boss.defense}\n` +
        `📊 المستوى: ${boss.level}\n` +
        `💰 جائزة: ${boss.reward_pool.toLocaleString()} ذهب\n\n` +
        `🎯 استخدم \`/boss\` للمشاركة في القتال!`,
        0xff0000
      );

      await interaction.reply({ embeds: [announceEmbed] });
      return;
    }

    const player = getPlayer(interaction.user.id, interaction.user.username);

    if (player.energy < 30) {
      return interaction.reply({ content: `❌ تحتاج 30 طاقة لقتال البوس! طاقتك: ${player.energy}/${player.max_energy}`, ephemeral: true });
    }

    // Check if already fought in last 5 minutes
    const recent = getQuery('SELECT * FROM world_boss_damage WHERE boss_id = ? AND user_id = ?', [boss.id, interaction.user.id]);

    updatePlayer(interaction.user.id, { energy: player.energy - 30 });

    // Calculate damage
    const atkResult = calculateDamage(player.attack, boss.defense, player.luck || 5, player.crit_chance || 5, player.crit_damage || 150, player.dodge_chance || 5);
    let damage = atkResult.damage + randomInt(5, 20);

    // Boost from active events
    const { getEventMultiplier } = require('../../database/db');
    damage = Math.round(damage * getEventMultiplier('atk'));

    // Elemental bonus (darkness vs light etc)
    const { getElementMultiplier } = require('../../utils/helpers');
    const elementMult = getElementMultiplier('ظلامي', 'نوراني');
    damage = Math.round(damage * elementMult);

    // Update boss HP
    const newHp = Math.max(0, boss.hp - damage);
    runQuery('UPDATE world_boss SET hp = ? WHERE id = ?', [newHp, boss.id]);

    // Track damage
    if (recent) {
      runQuery('UPDATE world_boss_damage SET damage = damage + ? WHERE boss_id = ? AND user_id = ?', [damage, boss.id, interaction.user.id]);
    } else {
      runQuery('INSERT INTO world_boss_damage (boss_id, user_id, damage) VALUES (?, ?, ?)', [boss.id, interaction.user.id, damage]);
    }

    // Calculate reward share
    const totalDamage = allQuery('SELECT SUM(damage) as total FROM world_boss_damage WHERE boss_id = ?', [boss.id])[0]?.total || damage;
    const myDamage = (recent?.damage || 0) + damage;
    const sharePercentage = myDamage / totalDamage;

    const hpBar = progressBar(newHp, boss.max_hp, 20);

    const embed = createBaseEmbed(`🐉 ${boss.name}`,
      `**${interaction.user.username}** يهاجم البوس!\n\n` +
      `${atkResult.isCrit ? '💥 **ضربة حرجة!** ' : '⚔️ '}تسبب بـ **${damage.toLocaleString()}** ضرر!\n` +
      `${atkResult.isDodged ? '💨 البوس تفادى!' : ''}\n\n` +
      `❤️ HP البوس:\n${hpBar}\n` +
      `**${newHp.toLocaleString()} / ${boss.max_hp.toLocaleString()}**\n\n` +
      `🏆 مساهمتك: ${Math.round(sharePercentage * 100)}%\n` +
      `💰 حصتك المتوقعة من الجائزة: ${Math.round(boss.reward_pool * sharePercentage).toLocaleString()} ذهب`,
      newHp <= 0 ? 0xffd700 : 0xff4444
    );

    if (newHp <= 0) {
      // Boss defeated!
      const participants = allQuery('SELECT wbd.*, p.username FROM world_boss_damage wbd JOIN players p ON wbd.user_id = p.user_id WHERE wbd.boss_id = ? ORDER BY wbd.damage DESC', [boss.id]);
      const totalDmg = participants.reduce((sum, p) => sum + p.damage, 0);

      let resultText = `🎉 **تم هزيمة ${boss.name}!**\n\n`;
      resultText += `**🏆 أفضل المقاتلين:**\n`;

      const medals = ['🥇', '🥈', '🥉'];
      participants.slice(0, 10).forEach((p, i) => {
        const medal = medals[i] || `${i + 1}.`;
        const share = Math.round((p.damage / totalDmg) * boss.reward_pool);
        resultText += `${medal} **${p.username}** - ${p.damage.toLocaleString()} ضرر - 💰 ${share.toLocaleString()} ذهب\n`;

        // Give rewards
        const pData = getQuery('SELECT * FROM players WHERE user_id = ?', [p.user_id]);
        if (pData) {
          updatePlayer(p.user_id, {
            gold: pData.gold + share,
            xp: pData.xp + Math.round(share * 0.5),
            shadow_essence: (pData.shadow_essence || 0) + Math.round(share * 0.1)
          });
        }
      });

      // Mark defeated
      runQuery('UPDATE world_boss SET defeated = 1, active = 0 WHERE id = ?', [boss.id]);

      // Achievement check
      for (const p of participants) {
        checkAchievements(p.user_id);
      }

      embed.setDescription(resultText);

      // New boss will spawn next time
      await interaction.reply({ embeds: [embed] });
    } else {
      const row = new ActionRowBuilder()
        .addComponents(
          new ButtonBuilder()
            .setCustomId('boss_attack')
            .setLabel('⚔️ هجوم آخر')
            .setStyle(ButtonStyle.Danger)
            .setDisabled(player.energy < 30)
        );

      await interaction.reply({ embeds: [embed], components: [row] });
    }
  }
};

