    .setName('dungeon')
    .setDescription('🚪 ادخل زنزانة الظل - واجه الأعداء واهزم البوسات'),

  async execute(interaction) {
    const player = getPlayer(interaction.user.id, interaction.user.username);

    const cd = checkCooldown(interaction.user.id, 'dungeon', 30);
    if (cd.onCooldown) {
      return interaction.reply({ content: `⏳ انتظر ${formatTime(cd.remaining)} قبل دخول الزنزانة مرة أخرى.`, ephemeral: true });
    }

    if (player.energy < 20) {
      return interaction.reply({ content: `❌ تحتاج 20 طاقة لدخول الزنزانة. طاقتك: ${player.energy}/${player.max_energy}`, ephemeral: true });
    }

    // Get or create dungeon progress
    let dungeon = getQuery('SELECT * FROM dungeon_progress WHERE user_id = ?', [interaction.user.id]);
    if (!dungeon) {
      runQuery('INSERT INTO dungeon_progress (user_id, health, max_hp) VALUES (?, ?, ?)', [interaction.user.id, player.health, player.max_health]);
      dungeon = getQuery('SELECT * FROM dungeon_progress WHERE user_id = ?', [interaction.user.id]);
    }

    const { getDungeonData } = require('../../database/db');
    const floors = getDungeonData();
    const currentFloor = Math.min(dungeon.current_floor || 1, floors.length);
    const floorData = floors[currentFloor - 1];

    // Deduct energy
    updatePlayer(interaction.user.id, { energy: player.energy - 20 });

    const embed = createBaseEmbed(`🚪 الزنزانة - الطابق ${currentFloor}`, 
      `**${floorData.name}**\n\n` +
      `**${interaction.user.username}** يدخل الزنزانة...\n\n` +
      `📍 الطابق: ${currentFloor}/10\n` +
      `❤️ صحتك: ${dungeon.health || player.health}/${player.max_health}\n` +
      `⚡ طاقتك: ${player.energy - 20}/${player.max_energy}\n\n` +
      `🎯 اختر مسارك:`,
      0x660000
    );

    const row = new ActionRowBuilder()
      .addComponents(
        new ButtonBuilder().setCustomId('dungeon_fight').setLabel('⚔️ قتال').setStyle(ButtonStyle.Danger),
        new ButtonBuilder().setCustomId('dungeon_heal').setLabel('💊 شفاء (50💰)').setStyle(ButtonStyle.Success),
        new ButtonBuilder().setCustomId('dungeon_flee').setLabel('🏃 خروج').setStyle(ButtonStyle.Secondary)
      );

    await interaction.reply({ embeds: [embed], components: [row] });

    // Handle button interactions
    const filter = i => i.customId.startsWith('dungeon_') && i.user.id === interaction.user.id;
    const collector = interaction.channel.createMessageComponentCollector({ filter, time: 120000 });

    let currentHp = dungeon.health || player.health;
    let floor = currentFloor;
    let maxFloor = dungeon.max_floor || 1;
    let kills = 0;
    let goldEarned = 0;
    let xpEarned = 0;
    let essenceEarned = 0;
    let loot = [];

    collector.on('collect', async (i) => {
      if (i.customId === 'dungeon_flee') {
        const resultEmbed = createBaseEmbed('🏃 خروج من الزنزانة',
          `**نتائج الزنزانة:**\n\n` +
          `🏆 الطابق: ${floor}\n` +
          `💀 قتلى: ${kills}\n` +
          `💰 ذهب: ${goldEarned}\n` +
          `📊 XP: ${xpEarned}\n` +
          `💎 جوهر الظل: ${essenceEarned}\n` +
          (loot.length > 0 ? `🎁 الغنائم: ${loot.join(', ')}` : ''),
          0x888888
        );

        // Save progress
        runQuery('UPDATE dungeon_progress SET current_floor = ?, max_floor = ?, health = ?, last_run = CURRENT_TIMESTAMP WHERE user_id = ?',
          [floor, maxFloor, currentHp, interaction.user.id]);

        // Update leaderboard
        runQuery('INSERT OR REPLACE INTO dungeon_leaderboard (user_id, best_floor, total_runs, total_kills) VALUES (?, ?, COALESCE((SELECT total_runs FROM dungeon_leaderboard WHERE user_id = ?), 0) + 1, COALESCE((SELECT total_kills FROM dungeon_leaderboard WHERE user_id = ?), 0) + ?)',
          [interaction.user.id, Math.max(maxFloor, floor || 1), interaction.user.id, interaction.user.id, kills]);

        collector.stop();
        return i.update({ embeds: [resultEmbed], components: [] });
      }

      if (i.customId === 'dungeon_heal') {
        const playerData = getPlayer(interaction.user.id, interaction.user.username);
        if (playerData.gold < 50) {
          return i.reply({ content: '❌ ليس لديك 50 ذهب للشفاء!', ephemeral: true });
        }
        if (currentHp >= playerData.max_health) {
          return i.reply({ content: '✅ صحتك كاملة بالفعل!', ephemeral: true });
        }
        const healAmount = 30;
        currentHp = Math.min(currentHp + healAmount, playerData.max_health);
        updatePlayer(interaction.user.id, { gold: playerData.gold - 50 });

        const healEmbed = createBaseEmbed('💊 شفاء', `تم شفاء ${healAmount} نقطة صحة.\n❤️ صحتك الآن: ${currentHp}/${playerData.max_health}`, 0x00ff88);
        return i.update({ embeds: [healEmbed], components: [] }).catch(() => {});
      }

      if (i.customId === 'dungeon_fight') {
        const playerData = getPlayer(interaction.user.id, interaction.user.username);

        // Pick a random enemy from this floor
        const enemies = floorData.enemies || [];
        const boss = floorData.boss;

        // Boss fight every 3 floors, or final floor
        const isBossFight = floor % 3 === 0 || floor === 10;
        const enemy = isBossFight ? boss : (enemies.length > 0 ? enemies[Math.floor(Math.random() * enemies.length)] : { name: 'وحش ظل', hp: 50, atk: 10, def: 5, reward: 20 });

        if (!enemy) {
          return i.reply({ content: '❌ خطأ في تحميل بيانات العدو!', ephemeral: true });
        }

        // Fight simulation
        let enemyHp = enemy.hp + randomInt(-5, 10);
        let fightLog = `⚔️ معركة ضد **${enemy.name}**!\n\n`;

        let playerAttack = playerData.attack;
        let playerDefense = playerData.defense;

        // Multi-hit battle
        let turns = 0;
        while (enemyHp > 0 && currentHp > 0 && turns < 20) {
          turns++;

          // Player turn
          const atkResult = calculateDamage(playerAttack, enemy.defense || 0, playerData.luck || 5, playerData.crit_chance || 5, playerData.crit_damage || 150, playerData.dodge_chance || 5);
          if (atkResult.isDodged) {
            fightLog += `⏭️ ${enemy.name} تفادى هجومك!\n`;
          } else {
            enemyHp -= atkResult.damage;
            const elementMult = 1.0; // Could add elemental effects
            fightLog += `${atkResult.isCrit ? '💥 **ضربة حرجة!** ' : '⚔️ '}هاجمت ${enemy.name} بـ ${Math.round(atkResult.damage * elementMult)} ضرر\n`;
          }

          if (enemyHp <= 0) {
            fightLog += `\n✨ **انتصار!** قتلت ${enemy.name}\n`;
            break;
          }

          // Enemy turn
          const enemyAtk = calculateDamage(enemy.attack || enemy.atk, playerDefense);
          if (enemyAtk.isDodged) {
            fightLog += `💨 تفاديت هجوم ${enemy.name}!\n`;
          } else {
            currentHp -= enemyAtk.damage;
            fightLog += `💥 ${enemy.name} يضربك بـ ${enemyAtk.damage} ضرر\n`;
          }
        }

        if (currentHp <= 0) {
          fightLog += `\n💀 **هزمت!** لقد انهارت في المعركة...\n`;
          const reward = Math.max(1, Math.floor(goldEarned * 0.5));
          goldEarned = Math.floor(goldEarned * 0.5);

          const defeatEmbed = createBaseEmbed('💀 هزيمة في الزنزانة',
            fightLog + `\nخسرت نصف ما جمعت.\n💰 المتبقي: ${goldEarned} ذهب`,
            0xff0000
          );

          runQuery('UPDATE dungeon_progress SET current_floor = 1, health = ?, last_run = CURRENT_TIMESTAMP WHERE user_id = ?',
            [playerData.max_health, interaction.user.id]);

          // Give partial rewards
          updatePlayer(interaction.user.id, {
            gold: playerData.gold + goldEarned,
            xp: playerData.xp + Math.floor(xpEarned * 0.5),
            shadow_essence: (playerData.shadow_essence || 0) + Math.floor(essenceEarned * 0.5),
            health: Math.max(1, currentHp)
          });

          collector.stop();
          return i.update({ embeds: [defeatEmbed], components: [] });
        }

        // Victory!
        const reward = enemy.reward || enemy.goldReward || randomInt(10, 30);
        const xpReward = enemy.xpReward || randomInt(5, 20);
        goldEarned += reward;
        xpEarned += xpReward;
        kills++;

        // Essence chance
        if (chance(20)) {
          essenceEarned += randomInt(1, 3);
        }

        // Loot chance
        if (chance(25)) {
          const lootItems = ['قطعة ظل', 'بلورة صغيرة', 'مسحوق عظام', 'ظل محارب', 'شظية نجم'];
          const lootItem = lootItems[Math.floor(Math.random() * lootItems.length)];
          loot.push(lootItem);
          addItem(interaction.user.id, 'material', lootItem, 'شائع');
        }

        // Boss kill bonus
        if (isBossFight) {
          const bossReward = boss.reward || 100;
          goldEarned += bossReward;
          xpEarned += 50;
          fightLog += `\n👑 **قهرت الزعيم!** مكافأة إضافية: ${bossReward}💰\n`;

          // Move to next floor
          if (floor < 10) {
            floor++;
            maxFloor = Math.max(maxFloor, floor);
            fightLog += `\n🚪 انتقلت إلى الطابق ${floor}!\n`;

            // Small heal between floors
            currentHp = Math.min(currentHp + 20, playerData.max_health);
          } else {
            fightLog += `\n🎉 **أكملت الزنزانة!** أنت أسطورة!\n`;
          }
        }

        // Check level up
        const { xpForLevel } = require('../../utils/helpers');
        const newTotalXp = playerData.xp + xpEarned;
        if (newTotalXp >= xpForLevel(playerData.level)) {
          const overflow = newTotalXp - xpForLevel(playerData.level);
          updatePlayer(interaction.user.id, {
            level: playerData.level + 1,
            xp: overflow,
            max_health: playerData.max_health + 10,
            health: playerData.max_health + 10,
            attack: playerData.attack + 2,
            defense: playerData.defense + 1,
            max_energy: playerData.max_energy + 5
          });
          currentHp = playerData.max_health + 10;
          fightLog += `\n🎉 **ارتقيت إلى المستوى ${playerData.level + 1}!**\n`;
        }

        updatePlayer(interaction.user.id, {
          gold: playerData.gold + goldEarned,
          xp: playerData.xp + xpEarned,
          shadow_essence: (playerData.shadow_essence || 0) + essenceEarned,
          health: currentHp
        });

        // Check achievements
        checkAchievements(interaction.user.id);

        const fightEmbed = createBaseEmbed(`⚔️ معركة - الطابق ${floor}`,
          fightLog +
          `\n❤️ صحتك: ${currentHp}/${playerData.max_health}\n` +
          `💰 الذهب: ${goldEarned} | 📊 XP: ${xpEarned} | 💎 الجوهر: ${essenceEarned}\n` +
          `💀 قتلى: ${kills}`,
          currentHp < 30 ? 0xff4444 : 0x00ff88
        );

        const nextRow = new ActionRowBuilder()
          .addComponents(
            new ButtonBuilder().setCustomId('dungeon_fight').setLabel('⚔️ استمرار القتال').setStyle(ButtonStyle.Danger),
            new ButtonBuilder().setCustomId('dungeon_heal').setLabel('💊 شفاء (50💰)').setStyle(ButtonStyle.Success),
            new ButtonBuilder().setCustomId('dungeon_flee').setLabel('🏃 خروج').setStyle(ButtonStyle.Secondary)
          );

        // If floor 10 boss defeated, auto-complete
        if (isBossFight && floor >= 10 && enemyHp <= 0) {
          const finalEmbed = createBaseEmbed('🎉 الزنزانة مكتملة!',
            `تهانينا! أكملت جميع الطوابق العشرة!\n\n` +
            `📊 النتائج النهائية:\n` +
            `💰 ذهب: ${goldEarned}\n` +
            `📊 XP: ${xpEarned}\n` +
            `💎 جوهر الظل: ${essenceEarned}\n` +
            `💀 قتلى: ${kills}\n` +
            (loot.length > 0 ? `🎁 الغنائم: ${loot.join(', ')}` : ''),
            0xffd700
          );

          // Bonus for completing all floors
          updatePlayer(interaction.user.id, {
            gold: playerData.gold + goldEarned + 500,
            xp: playerData.xp + xpEarned + 200,
            shadow_essence: (playerData.shadow_essence || 0) + essenceEarned + 50
          });

          runQuery('UPDATE dungeon_progress SET current_floor = 1, max_floor = 10, health = ? WHERE user_id = ?',
            [playerData.max_health, interaction.user.id]);

          collector.stop();
          return i.update({ embeds: [finalEmbed], components: [] });
        }

        // Continue dungeon
        if (floor < 10 && isBossFight) {
          // Update floor data for next round
          runQuery('UPDATE dungeon_progress SET current_floor = ?, max_floor = ?, health = ? WHERE user_id = ?',
            [floor, maxFloor, currentHp, interaction.user.id]);
        }

        await i.update({ embeds: [fightEmbed], components: floor < 10 ? [nextRow] : [] });
      }
    });

    collector.on('end', async (collected, reason) => {
      if (reason === 'time') {
        try {
          await interaction.editReply({ components: [] });
        } catch (e) {}
      }
    });
  }
};

const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer, getShadows, addShadow, runQuery, checkAchievements } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { randomInt, chance, generateShadowName, generateShadowType, generateRarity } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('fuse')
    .setDescription('🔮 دمج مخلوقين ظل للحصول على مخلوق أقوى')
    .addIntegerOption(o => o.setName('shadow1').setDescription('رقم المخلوق الأول').setRequired(true).setMinValue(1))
    .addIntegerOption(o => o.setName('shadow2').setDescription('رقم المخلوق الثاني').setRequired(true).setMinValue(1)),

  async execute(interaction) {
    const shadows = getShadows(interaction.user.id);

    if (shadows.length < 2) {
      return interaction.reply({ content: '❌ تحتاج مخلوقين ظل على الأقل للدمج!', ephemeral: true });
    }

    const idx1 = interaction.options.getInteger('shadow1') - 1;
    const idx2 = interaction.options.getInteger('shadow2') - 1;

    if (idx1 < 0 || idx1 >= shadows.length || idx2 < 0 || idx2 >= shadows.length) {
      return interaction.reply({ content: '❌ أرقام المخلوقات غير صحيحة!', ephemeral: true });
    }

    if (idx1 === idx2) {
      return interaction.reply({ content: '❌ لا يمكنك دمج مخلوق مع نفسه!', ephemeral: true });
    }

    const shadow1 = shadows[idx1];
    const shadow2 = shadows[idx2];

    const player = getPlayer(interaction.user.id, interaction.user.username);

    if (player.gold < 1000) {
      return interaction.reply({ content: '❌ تحتاج 1000 ذهب لعملية الدمج!', ephemeral: true });
    }

    const embed = createBaseEmbed('🔮 دمج الظلال',
      `**${shadow1.shadow_name}** (مستوى ${shadow1.level} - ${shadow1.rarity})\n` +
      `➕\n` +
      `**${shadow2.shadow_name}** (مستوى ${shadow2.level} - ${shadow2.rarity})\n\n` +
      `💰 التكلفة: 1000 ذهب\n` +
      `📊 فرصة النجاح: ${shadow1.rarity === 'خرافي' || shadow2.rarity === 'خرافي' ? 40 : shadow1.rarity === 'أسطوري' || shadow2.rarity === 'أسطوري' ? 55 : 75}%\n\n` +
      `هل تريد المتابعة؟`,
      0xaa44ff
    );

    const row = new ActionRowBuilder()
      .addComponents(
        new ButtonBuilder().setCustomId('fuse_confirm').setLabel('🔮 دمج!').setStyle(ButtonStyle.Primary),
        new ButtonBuilder().setCustomId('fuse_cancel').setLabel('❌ إلغاء').setStyle(ButtonStyle.Danger)
      );

    await interaction.reply({ embeds: [embed], components: [row] });

    const filter = i => i.customId.startsWith('fuse_') && i.user.id === interaction.user.id;
    try {
      const response = await interaction.channel.awaitMessageComponent({ filter, time: 30000 });

      if (response.customId === 'fuse_cancel') {
        return response.update({ embeds: [createBaseEmbed('❌ ألغي', 'تم إلغاء الدمج.', 0x888888)], components: [] });
      }

      // Process fusion
      updatePlayer(interaction.user.id, { gold: player.gold - 1000 });

      // Calculate result
      const successChance = shadow1.rarity === 'خرافي' || shadow2.rarity === 'خرافي' ? 40 : 
                            shadow1.rarity === 'أسطوري' || shadow2.rarity === 'أسطوري' ? 55 : 75;

      const levelAvg = Math.floor((shadow1.level + shadow2.level) / 2) + randomInt(1, 3);
      const rarityUp = chance(successChance);

      let resultRarity;
      if (rarityUp) {
        // Higher rarity
        const rarities = ['شائع', 'نادر', 'أسطوري', 'خرافي'];
        const maxRarity = Math.max(rarities.indexOf(shadow1.rarity), rarities.indexOf(shadow2.rarity));
        const newRarityIdx = Math.min(maxRarity + 1, rarities.length - 1);
        resultRarity = rarities[newRarityIdx];
      } else {
        // Lower or same
        const rarities = ['شائع', 'نادر', 'أسطوري', 'خرافي'];
        const maxRarity = Math.max(rarities.indexOf(shadow1.rarity), rarities.indexOf(shadow2.rarity));
        const newRarityIdx = Math.max(0, maxRarity - randomInt(0, 1));
        resultRarity = rarities[newRarityIdx];
      }

      const newName = generateShadowName();
      const newType = randomInt(0, 1) ? shadow1.shadow_type : shadow2.shadow_type;

      // Delete old shadows
      const { runQuery } = require('../../database/db');
      runQuery('DELETE FROM shadows WHERE id = ?', [shadow1.id]);
      runQuery('DELETE FROM shadows WHERE id = ?', [shadow2.id]);

      // Create new shadow
      const newShadowId = addShadow(interaction.user.id, newName, newType, resultRarity, levelAvg);

      // Record fusion
      runQuery('INSERT INTO shadow_fusions (user_id, result_shadow_id) VALUES (?, ?)', [interaction.user.id, newShadowId]);

      // Check achievements
      checkAchievements(interaction.user.id);

      const resultEmbed = createBaseEmbed(rarityUp ? '🎉 **دمج ناجح!**' : '⚠️ **دمج... مقبول**',
        `**${shadow1.shadow_name}** + **${shadow2.shadow_name}**\n\n` +
        `${rarityUp ? '✨ اندمجت الظلال لتخلق مخلوقاً أقوى!' : '🔀 اندمجت الظلال ولكن النتيجة ليست كما توقعت...'}\n\n` +
        `**⬇️ النتيجة ⬇️**\n` +
        `👾 **${newName}**\n` +
        `🔮 النوع: ${newType}\n` +
        `⭐ الندرة: ${resultRarity} ${rarityUp ? '⬆️' : '➡️'}\n` +
        `📊 المستوى: ${levelAvg}`,
        rarityUp ? 0xaa44ff : 0x888888
      );

      await response.update({ embeds: [resultEmbed], components: [] });

    } catch (e) {
      if (e.code !== 'INTERACTION_COLLECTOR_ERROR') {
        await interaction.editReply({ embeds: [createBaseEmbed('⏰ انتهى الوقت', 'لم تختر شيئاً.', 0x888888)], components: [] }).catch(() => {});
      }
    }
  }
};

const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer, buyLotteryTicket, getLotteryStats, drawLottery, allQuery, runQuery, checkAchievements } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { randomInt, chance, checkCooldown, formatTime } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('gamble')
    .setDescription('🎲 ألعاب الحظ - يانصيب، زهر، عملة')
    .addSubcommand(sub =>
      sub.setName('dice')
        .setDescription('🎲 لعب الزهر - اربح ذهباً')
        .addIntegerOption(o => o.setName('bet').setDescription('الرهان').setRequired(true).setMinValue(10)))
    .addSubcommand(sub =>
      sub.setName('coinflip')
        .setDescription('🪙 قلب عملة - مضاعفة الرهان')
        .addStringOption(o => o.setName('choice').setDescription('اختر').setRequired(true).addChoices({ name: 'وجه', value: 'وجه' }, { name: 'كتابة', value: 'كتابة' }))
        .addIntegerOption(o => o.setName('bet').setDescription('الرهان').setRequired(true).setMinValue(10)))
    .addSubcommand(sub =>
      sub.setName('lottery')
        .setDescription('🍀 شراء تذكرة يانصيب - اربح الجائزة الكبرى!')
        .addIntegerOption(o => o.setName('tickets').setDescription('عدد التذاكر (1-10)').setRequired(false).setMinValue(1).setMaxValue(10))),

  async execute(interaction) {
    const sub = interaction.options.getSubcommand();

    if (sub === 'dice') {
      const bet = interaction.options.getInteger('bet');
      const player = getPlayer(interaction.user.id, interaction.user.username);

      if (player.gold < bet) return interaction.reply({ content: `❌ ليس لديك ${bet} ذهب!`, ephemeral: true });

      const playerRoll = randomInt(1, 6) + randomInt(1, 6);
      const botRoll = randomInt(1, 6) + randomInt(1, 6);

      let won = false;
      let winnings = 0;

      if (playerRoll > botRoll) {
        won = true;
        winnings = Math.floor(bet * 1.8);
        updatePlayer(interaction.user.id, { gold: player.gold + winnings - bet });
      } else if (playerRoll === botRoll) {
        winnings = bet; // Draw - return bet
      } else {
        updatePlayer(interaction.user.id, { gold: player.gold - bet });
      }

      const embed = createBaseEmbed('🎲 زهر الظل',
        `🎲 **${interaction.user.username}** : ${playerRoll}\n` +
        `🎲 **الخصم** : ${botRoll}\n\n` +
        `${won ? `🎉 **ربحت!** +${winnings - bet}💰` : playerRoll === botRoll ? '🤝 **تعادل!** استرداد رهانك.' : '💔 **خسرت!**'} ` +
        `\n💰 رصيدك: ${won ? player.gold + winnings - bet : playerRoll === botRoll ? player.gold : player.gold - bet}`,
        won ? 0x00ff88 : playerRoll === botRoll ? 0xffaa00 : 0xff4444
      );

      await interaction.reply({ embeds: [embed] });

    } else if (sub === 'coinflip') {
      const choice = interaction.options.getString('choice');
      const bet = interaction.options.getInteger('bet');
      const player = getPlayer(interaction.user.id, interaction.user.username);

      if (player.gold < bet) return interaction.reply({ content: `❌ ليس لديك ${bet} ذهب!`, ephemeral: true });

      const result = chance(50) ? 'وجه' : 'كتابة';
      const won = result === choice;

      if (won) {
        const winnings = Math.floor(bet * 1.9);
        updatePlayer(interaction.user.id, { gold: player.gold + winnings - bet });
        const embed = createBaseEmbed('🪙 قلب عملة',
          `🪙 سقطت: **${result}**\n` +
          `🎯 اخترت: **${choice}**\n\n` +
          `🎉 **ربحت!** +${winnings - bet}💰\n` +
          `💰 رصيدك: ${player.gold + winnings - bet}`,
          0x00ff88
        );
        await interaction.reply({ embeds: [embed] });
      } else {
        updatePlayer(interaction.user.id, { gold: player.gold - bet });
        const embed = createBaseEmbed('🪙 قلب عملة',
          `🪙 سقطت: **${result}**\n` +
          `🎯 اخترت: **${choice}**\n\n` +
          `💔 **خسرت!** -${bet}💰\n` +
          `💰 رصيدك: ${player.gold - bet}`,
          0xff4444
        );
        await interaction.reply({ embeds: [embed] });
      }

    } else if (sub === 'lottery') {
      const tickets = interaction.options.getInteger('tickets') || 1;
      const player = getPlayer(interaction.user.id, interaction.user.username);
      const cost = tickets * 500;

      if (player.gold < cost) return interaction.reply({ content: `❌ تحتاج ${cost} ذهب لشراء ${tickets} تذاكر!`, ephemeral: true });

      updatePlayer(interaction.user.id, { gold: player.gold - cost });

      for (let i = 0; i < tickets; i++) {
        buyLotteryTicket(interaction.user.id);
      }

      const stats = getLotteryStats();
      const totalTickets = stats.total || 0;

      const embed = createBaseEmbed('🍀 يانصيب الظل',
        `اشتريت **${tickets}** تذكرة يانصيب!\n\n` +
        `📊 إجمالي التذاكر: ${totalTickets}\n` +
        `🏆 الجائزة الكبرى: ${(totalTickets * 500 * 0.8).toLocaleString()} 💰\n\n` +
        `🍀 حظاً موفقاً! سيتم سحب اليانصيب قريباً.`,
        0xffd700
      );

      await interaction.reply({ embeds: [embed] });
    }
  }
};

const { SlashCommandBuilder, ActionRowBuilder, StringSelectMenuBuilder, StringSelectMenuOptionBuilder } = require('discord.js');
const { getPlayer, updatePlayer, getInventory, getMarketListings, getMyListings, createListing, removeListing, getQuery } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('market')
    .setDescription('🏪 سوق الظل - اشترِ وبع العناصر مع اللاعبين الآخرين')
    .addSubcommand(sub =>
      sub.setName('browse')
        .setDescription('تصفح السوق'))
    .addSubcommand(sub =>
      sub.setName('sell')
        .setDescription('بيع عنصر من مخزونك')
        .addStringOption(o => o.setName('item').setDescription('اسم العنصر').setRequired(true))
        .addIntegerOption(o => o.setName('price').setDescription('السعر بالذهب').setRequired(true).setMinValue(1)))
    .addSubcommand(sub =>
      sub.setName('my')
        .setDescription('عرض عناصرك المعروضة للبيع'))
    .addSubcommand(sub =>
      sub.setName('buy')
        .setDescription('شراء عنصر من السوق')
        .addIntegerOption(o => o.setName('id').setDescription('رقم العرض').setRequired(true)))
    .addSubcommand(sub =>
      sub.setName('cancel')
        .setDescription('إلغاء عرض بيع')
        .addIntegerOption(o => o.setName('id').setDescription('رقم العرض').setRequired(true))),

  async execute(interaction) {
    const sub = interaction.options.getSubcommand();

    if (sub === 'browse') {
      const page = 1;
      const listings = getMarketListings(page);

      if (listings.length === 0) {
        return interaction.reply({ content: '❌ السوق فارغ! كن أول من يبيع باستخدام `/market sell`.', ephemeral: true });
      }

      const rarityEmojis = { 'شائع': '⬜', 'نادر': '🟦', 'أسطوري': '🟨', 'خرافي': '🟪' };

      let desc = listings.map(l => 
        `\`#${l.id}\` ${rarityEmojis[l.item_rarity] || '⬜'} **${l.item_name}** ×${l.quantity}\n` +
        `   🏷️ ${l.price.toLocaleString()}💰 | البائع: ${l.username || 'مجهول'} | ${l.item_rarity}`
      ).join('\n\n');

      const embed = createBaseEmbed('🏪 سوق الظل', desc, 0xffd700)
        .setFooter({ text: 'استخدم /market buy [id] للشراء • الصفحة 1' });

      await interaction.reply({ embeds: [embed] });

    } else if (sub === 'sell') {
      const itemName = interaction.options.getString('item');
      const price = interaction.options.getInteger('price');

      const inv = getInventory(interaction.user.id);
      const item = inv.find(i => i.item_name === itemName || i.item_name.includes(itemName));

      if (!item) {
        return interaction.reply({ content: '❌ لم أجد هذا العنصر في مخزونك!', ephemeral: true });
      }

      if (item.equipped) {
        return interaction.reply({ content: '❌ لا يمكن بيع عنصر مجهز!', ephemeral: true });
      }

      createListing(interaction.user.id, item.item_name, item.item_type, item.item_rarity, 1, item.stats, price);

      // Remove from inventory
      const { removeItem } = require('../../database/db');
      removeItem(item.id);

      const embed = createBaseEmbed('✅ تم العرض', 
        `**${item.item_name}** معروض للبيع بـ **${price.toLocaleString()}** 💰\n` +
        `سيتم إخطارك عند البيع.`,
        0x00ff88
      );
      await interaction.reply({ embeds: [embed] });

    } else if (sub === 'my') {
      const listings = getMyListings(interaction.user.id);

      if (listings.length === 0) {
        return interaction.reply({ content: '❌ ليس لديك عناصر معروضة للبيع. استخدم `/market sell`.', ephemeral: true });
      }

      let desc = listings.map(l => 
        `\`#${l.id}\` **${l.item_name}** ×${l.quantity} | ${l.price.toLocaleString()}💰 | ${l.item_rarity}\n` +
        `   📅 ${l.listed_at}`
      ).join('\n\n');

      const embed = createBaseEmbed('📦 عروضي', desc, 0x00aaff)
        .setFooter({ text: 'استخدم /market cancel [id] للإلغاء' });
      await interaction.reply({ embeds: [embed] });

    } else if (sub === 'buy') {
      const listingId = interaction.options.getInteger('id');
      const listing = getQuery('SELECT * FROM market_listings WHERE id = ?', [listingId]);

      if (!listing) {
        return interaction.reply({ content: '❌ هذا العرض غير موجود!', ephemeral: true });
      }

      if (listing.seller_id === interaction.user.id) {
        return interaction.reply({ content: '❌ لا يمكنك شراء عنصرك الخاص!', ephemeral: true });
      }

      const buyer = getPlayer(interaction.user.id, interaction.user.username);

      if (buyer.gold < listing.price) {
        return interaction.reply({ content: `❌ ليس لديك ${listing.price.toLocaleString()} ذهب!`, ephemeral: true });
      }

      // Process transaction
      updatePlayer(interaction.user.id, { gold: buyer.gold - listing.price });

      const seller = getQuery('SELECT * FROM players WHERE user_id = ?', [listing.seller_id]);
      if (seller) {
        // 10% market tax
        const tax = Math.floor(listing.price * 0.1);
        const sellerGets = listing.price - tax;
        updatePlayer(listing.seller_id, { gold: seller.gold + sellerGets });
      }

      // Add item to buyer
      const { addItem } = require('../../database/db');
      addItem(interaction.user.id, listing.item_type, listing.item_name, listing.item_rarity, listing.quantity, listing.stats);

      // Remove listing
      removeListing(listingId, listing.seller_id);

      const embed = createBaseEmbed('✅ تم الشراء!',
        `اشتريت **${listing.item_name}** (${listing.item_rarity})\n` +
        `💰 السعر: ${listing.price.toLocaleString()} ذهب\n` +
        `📦 تمت إضافة العنصر إلى مخزونك.`,
        0x00ff88
      );
      await interaction.reply({ embeds: [embed] });

    } else if (sub === 'cancel') {
      const listingId = interaction.options.getInteger('id');
      const listing = removeListing(listingId, interaction.user.id);

      if (!listing) {
        return interaction.reply({ content: '❌ لم أجد هذا العرض أو ليس لك!', ephemeral: true });
      }

      // Return item to seller
      const { addItem } = require('../../database/db');
      addItem(interaction.user.id, listing.item_type, listing.item_name, listing.item_rarity, listing.quantity, listing.stats);

      const embed = createBaseEmbed('✅ تم إلغاء العرض', `تم إرجاع **${listing.item_name}** إلى مخزونك.`, 0x888888);
      await interaction.reply({ embeds: [embed] });
    }
  }
};

const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer, runQuery, checkAchievements } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { canPrestige, doPrestige, getPrestigeCost } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('prestige')
    .setDescription('🌀 نظام التمرير - ابدأ من جديد بمكافآت دائمة وقوية'),

  async execute(interaction) {
    const player = getPlayer(interaction.user.id, interaction.user.username);
    const currentPrestige = player.prestige || 0;

    if (!canPrestige(player)) {
      const cost = getPrestigeCost(currentPrestige + 1);
      return interaction.reply({
        content: `❌ شروط التمرير:\n` +
          `📊 المستوى: ${player.level}/50\n` +
          `💰 الذهب: ${player.gold.toLocaleString()}/${cost.toLocaleString()}\n` +
          `🔄 التمرير الحالي: ${currentPrestige}`,
        ephemeral: true
      });
    }

    const result = doPrestige(player);

    const embed = createBaseEmbed('🌀 **تمرير المستوى!**',
      `**${interaction.user.username}** يمرر مستواه!\n\n` +
      `🔄 من التمرير ${currentPrestige} → ${result.newPrestige}\n` +
      `💰 التكلفة: ${result.cost.toLocaleString()} ذهب\n\n` +
      `**المكافآت الدائمة:**\n` +
      `❤️ صحة: +${result.bonuses.max_health}\n` +
      `⚔️ هجوم: +${result.bonuses.attack}\n` +
      `🛡️ دفاع: +${result.bonuses.defense}\n` +
      `⚡ طاقة: +${result.bonuses.energy}\n` +
      `🍀 حظ: +${result.bonuses.luck}\n\n` +
      `سيتم إعادة تعيين مستواك إلى 1، ذهبك إلى 500، لكن مخلوقات الظل ومخزونك سيبقى!`,
      0xaa44ff
    );

    const row = new ActionRowBuilder()
      .addComponents(
        new ButtonBuilder().setCustomId('prestige_confirm').setLabel('🌀 تمرير!').setStyle(ButtonStyle.Danger),
        new ButtonBuilder().setCustomId('prestige_cancel').setLabel('❌ إلغاء').setStyle(ButtonStyle.Secondary)
      );

    await interaction.reply({ embeds: [embed], components: [row] });

    const filter = i => i.customId.startsWith('prestige_') && i.user.id === interaction.user.id;
    try {
      const response = await interaction.channel.awaitMessageComponent({ filter, time: 30000 });

      if (response.customId === 'prestige_cancel') {
        return response.update({ embeds: [createBaseEmbed('❌ ألغي', 'تم إلغاء التمرير.', 0x888888)], components: [] });
      }

      // Apply prestige
      updatePlayer(interaction.user.id, {
        prestige: result.newPrestige,
        level: 1,
        xp: 0,
        gold: 500,
        health: result.bonuses.max_health + 100,
        max_health: result.bonuses.max_health + 100,
        attack: result.bonuses.attack + 10,
        defense: result.bonuses.defense + 5,
        max_energy: result.bonuses.energy + 100,
        energy: result.bonuses.energy + 100,
        luck: (player.luck || 5) + result.bonuses.luck,
        gold: player.gold - result.cost
      });

      checkAchievements(interaction.user.id);

      const successEmbed = createBaseEmbed('🌀 **تم التمرير بنجاح!**',
        `**${interaction.user.username}** الآن في التمرير ${result.newPrestige}! 🎉\n\n` +
        `لقد أصبحت أقوى مما مضى! ابدأ رحلتك من جديد بمكافآت دائمة!`,
        0xaa44ff
      );

      await response.update({ embeds: [successEmbed], components: [] });

    } catch (e) {
      if (e.code !== 'INTERACTION_COLLECTOR_ERROR') {
        await interaction.editReply({ content: '⏰ انتهى الوقت.', components: [] }).catch(() => {});
      }
    }
  }
};

const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, getQuests, updatePlayer } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('quests')
    .setDescription('📋 عرض المهام اليومية والمهام المتاحة'),

  async execute(interaction) {
    const player = getPlayer(interaction.user.id, interaction.user.username);
    const quests = getQuests(interaction.user.id);

    if (quests.length === 0) {
      const embed = createBaseEmbed('📋 لا توجد مهام', 'لا توجد مهام متاحة اليوم. عد غداً!', 0x888888);
      return interaction.reply({ embeds: [embed] });
    }

    const { dailyQuests } = require('../../utils/helpers');

    let description = `**📋 مهام اليوم - ${interaction.user.username}**\n\n`;

    let completedCount = 0;
    let totalRewards = { gold: 0, xp: 0, essence: 0 };

    for (const quest of quests) {
      // Find the quest definition by matching the key prefix
      const questDef = dailyQuests.find(q => quest.quest_key.startsWith(q.key));
      if (!questDef) continue;

      const progress = quest.progress || 0;
      const target = quest.target || 1;
      const completed = quest.completed;

      if (completed) completedCount++;

      const bar = '█'.repeat(Math.round((progress / target) * 10)) + '░'.repeat(10 - Math.round((progress / target) * 10));
      const status = completed ? '✅ **مكتمل**' : `⏳ ${bar} ${progress}/${target}`;

      description += `**${questDef.name}**\n`;
      description += `📝 ${questDef.desc}\n`;
      description += `${status}\n`;
      if (completed && !quest.reward_claimed) {
        // Auto-claim
        const reward = questDef.reward;
        totalRewards.gold += reward.gold;
        totalRewards.xp += reward.xp;
        totalRewards.essence += reward.essence;
        description += `🎁 المكافأة: ${reward.gold}💰 ${reward.xp}📊 ${reward.essence}💎\n`;
        // Mark as claimed
        const { runQuery } = require('../../database/db');
        runQuery('UPDATE quests SET reward_claimed = 1 WHERE id = ?', [quest.id]);
      }
      description += '\n';
    }

    if (totalRewards.gold > 0 || totalRewards.xp > 0) {
      updatePlayer(interaction.user.id, {
        gold: player.gold + totalRewards.gold,
        xp: player.xp + totalRewards.xp,
        shadow_essence: (player.shadow_essence || 0) + totalRewards.essence
      });
      description += `\n🎉 **تم استلام المكافآت تلقائياً!**\n`;
      description += `💰 +${totalRewards.gold} ذهب | 📊 +${totalRewards.xp} XP | 💎 +${totalRewards.essence} جوهر\n`;
    }

    description += `\n**✅ المنجز: ${completedCount}/${quests.length}**`;

    const embed = createBaseEmbed(`📋 مهام ${interaction.user.username}`, description, 0x00aaff);
    await interaction.reply({ embeds: [embed] });
  }
};

const { SlashCommandBuilder, ActionRowBuilder, StringSelectMenuBuilder, StringSelectMenuOptionBuilder } = require('discord.js');
const { getPlayer, updatePlayer, getSkills, runQuery } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { specializations, specializationBonuses } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('specialize')
    .setDescription('⚡ اختر تخصصك - مقاتل، ساحر، صياد، أو زعيم'),

  async execute(interaction) {
    const skills = getSkills(interaction.user.id);
    const currentSpec = skills.specialization || 'مقاتل';

    const select = new StringSelectMenuBuilder()
      .setCustomId('spec_select')
      .setPlaceholder('🎯 اختر تخصصك...')
      .addOptions(
        Object.entries(specializations).map(([key, val]) =>
          new StringSelectMenuOptionBuilder()
            .setLabel(key === currentSpec ? `${key} (حالياً)` : key)
            .setValue(key)
            .setDescription(val.desc)
            .setEmoji(key === 'مقاتل' ? '⚔️' : key === 'ساحر' ? '🔮' : key === 'صياد' ? '🏹' : '👑')
        )
      );

    const row = new ActionRowBuilder().addComponents(select);

    let desc = '🎯 **اختر تخصصك بحكمة!**\nالتخصص يمنح مكافآت دائمة.\n\n';
    for (const [key, val] of Object.entries(specializations)) {
      const bonus = specializationBonuses[key];
      const isCurrent = key === currentSpec;
      desc += `${isCurrent ? '✅' : '▪️'} **${key}** - ${val.desc}\n`;
      desc += `   ❤️ +${bonus.max_health} | ⚔️ +${bonus.attack} | 🛡️ +${bonus.defense}`;
      if (bonus.crit_chance) desc += ` | 💥 +${bonus.crit_chance}% crit`;
      if (bonus.dodge_chance) desc += ` | 💨 +${bonus.dodge_chance}% dodge`;
      if (bonus.luck) desc += ` | 🍀 +${bonus.luck} luck`;
      desc += '\n\n';
    }

    const embed = createBaseEmbed('⚡ التخصصات', desc, 0x00aaff);

    await interaction.reply({ embeds: [embed], components: [row] });

    const filter = i => i.customId === 'spec_select' && i.user.id === interaction.user.id;
    try {
      const selection = await interaction.channel.awaitMessageComponent({ filter, time: 30000 });
      const chosen = selection.values[0];

      if (chosen === currentSpec) {
        return selection.update({ embeds: [createBaseEmbed('⚡ تخصصك الحالي', `أنت بالفعل ${currentSpec}!`, 0x888888)], components: [] });
      }

      const bonus = specializationBonuses[chosen];

      // Apply spec bonuses (replace old bonuses)
      const player = getPlayer(interaction.user.id, interaction.user.username);
      const oldBonus = specializationBonuses[currentSpec];

      const newStats = {
        max_health: Math.max(100, player.max_health - (oldBonus?.max_health || 0) + (bonus.max_health || 0)),
        health: Math.max(100, player.health - (oldBonus?.max_health || 0) + (bonus.max_health || 0)),
        attack: Math.max(5, player.attack - (oldBonus?.attack || 0) + (bonus.attack || 0)),
        defense: Math.max(1, player.defense - (oldBonus?.defense || 0) + (bonus.defense || 0)),
        crit_chance: Math.max(0, (player.crit_chance || 5) - (oldBonus?.crit_chance || 0) + (bonus.crit_chance || 0)),
        dodge_chance: Math.max(0, (player.dodge_chance || 5) - (oldBonus?.dodge_chance || 0) + (bonus.dodge_chance || 0)),
        luck: Math.max(0, (player.luck || 5) - (oldBonus?.luck || 0) + (bonus.luck || 0)),
      };

      updatePlayer(interaction.user.id, newStats);
      runQuery('UPDATE player_skills SET specialization = ? WHERE user_id = ?', [chosen, interaction.user.id]);

      const resultEmbed = createBaseEmbed('✅ تم تغيير التخصص!',
        `**${currentSpec}** → **${chosen}**\n\n` +
        `🔄 تم تطبيق مكافآت التخصص الجديد!`,
        0x00ff88
      );

      await selection.update({ embeds: [resultEmbed], components: [] });

    } catch (e) {
      if (e.code !== 'INTERACTION_COLLECTOR_ERROR') {
        // ignore timeout
      }
    }
  }
};

const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, getFriends, getFriendRequests, sendFriendRequest, acceptFriendRequest, removeFriend } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('friend')
    .setDescription('🤝 نظام الأصدقاء')
    .addSubcommand(sub =>
      sub.setName('add')
        .setDescription('إرسال طلب صداقة')
        .addUserOption(o => o.setName('user').setDescription('اللاعب').setRequired(true)))
    .addSubcommand(sub =>
      sub.setName('accept')
        .setDescription('قبول طلب صداقة')
        .addUserOption(o => o.setName('user').setDescription('اللاعب').setRequired(true)))
    .addSubcommand(sub =>
      sub.setName('list')
        .setDescription('عرض قائمة الأصدقاء'))
    .addSubcommand(sub =>
      sub.setName('requests')
        .setDescription('عرض طلبات الصداقة'))
    .addSubcommand(sub =>
      sub.setName('remove')
        .setDescription('إزالة صديق')
        .addUserOption(o => o.setName('user').setDescription('اللاعب').setRequired(true))),

  async execute(interaction) {
    const sub = interaction.options.getSubcommand();

    if (sub === 'add') {
      const target = interaction.options.getUser('user');
      if (target.id === interaction.user.id) return interaction.reply({ content: '❌ لا يمكنك إضافة نفسك!', ephemeral: true });
      if (target.bot) return interaction.reply({ content: '❌ لا يمكنك إضافة بوت!', ephemeral: true });

      const result = sendFriendRequest(interaction.user.id, target.id);
      if (!result) return interaction.reply({ content: '❌ الطلب موجود بالفعل أو أنتما صديقان!', ephemeral: true });

      const embed = createBaseEmbed('🤝 طلب صداقة', `تم إرسال طلب صداقة إلى **${target.username}**!`, 0x00aaff);
      await interaction.reply({ embeds: [embed] });

      // Try to DM the target
      try {
        await target.send(`📨 **${interaction.user.username}** أرسل لك طلب صداقة في ممالك الظل!\nاستخدم \`/friend accept\` في السيرفر للقبول.`);
      } catch (e) {}

    } else if (sub === 'accept') {
      const target = interaction.options.getUser('user');
      const result = acceptFriendRequest(interaction.user.id, target.id);
      if (!result) return interaction.reply({ content: '❌ لا يوجد طلب صداقة من هذا الشخص!', ephemeral: true });

      const embed = createBaseEmbed('✅ صداقة جديدة!', `أنت و **${target.username}** أصبحتما صديقين الآن! 🎉`, 0x00ff88);
      await interaction.reply({ embeds: [embed] });

    } else if (sub === 'list') {
      const friends = getFriends(interaction.user.id);
      if (friends.length === 0) return interaction.reply({ content: '❌ ليس لديك أصدقاء بعد. استخدم `/friend add`.', ephemeral: true });

      const desc = friends.map(f => `👤 **${f.username}** - المستوى ${f.level}`).join('\n');
      const embed = createBaseEmbed(`👥 أصدقاء ${interaction.user.username} (${friends.length})`, desc, 0x00aaff);
      await interaction.reply({ embeds: [embed] });

    } else if (sub === 'requests') {
      const requests = getFriendRequests(interaction.user.id);
      if (requests.length === 0) return interaction.reply({ content: '✅ ليس لديك طلبات صداقة معلقة.', ephemeral: true });

      const desc = requests.map(r => `📨 **${r.username}** - استخدم \`/friend accept ${r.username}\``).join('\n');
      const embed = createBaseEmbed('📨 طلبات الصداقة', desc, 0xffaa00);
      await interaction.reply({ embeds: [embed] });

    } else if (sub === 'remove') {
      const target = interaction.options.getUser('user');
      removeFriend(interaction.user.id, target.id);
      const embed = createBaseEmbed('👋 تمت الإزالة', `تمت إزالة **${target.username}** من قائمة أصدقائك.`, 0x888888);
      await interaction.reply({ embeds: [embed] });
    }
  }
};

const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer, getMarriage, marryUsers, divorceUsers, getQuery, addItem, checkAchievements } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('marry')
    .setDescription('💑 نظام الزواج - تزوج لاعباً آخر في عالم الظل')
    .addSubcommand(sub =>
      sub.setName('propose')
        .setDescription('تقديم طلب زواج')
        .addUserOption(o => o.setName('partner').setDescription('الشخص الذي تريد الزواج منه').setRequired(true)))
    .addSubcommand(sub =>
      sub.setName('accept')
        .setDescription('قبول طلب الزواج')
        .addUserOption(o => o.setName('partner').setDescription('الشخص الذي قدم الطلب').setRequired(true)))
    .addSubcommand(sub =>
      sub.setName('info')
        .setDescription('عرض معلومات الزواج'))
    .addSubcommand(sub =>
      sub.setName('divorce')
        .setDescription('الطلاق - إنهاء الزواج')),

  async execute(interaction) {
    const sub = interaction.options.getSubcommand();

    if (sub === 'propose') {
      const partner = interaction.options.getUser('partner');
      if (partner.id === interaction.user.id) return interaction.reply({ content: '❌ لا يمكنك الزواج من نفسك!', ephemeral: true });
      if (partner.bot) return interaction.reply({ content: '❌ لا يمكنك الزواج من بوت!', ephemeral: true });

      const existing = getMarriage(interaction.user.id);
      if (existing) return interaction.reply({ content: '❌ أنت متزوج بالفعل! استخدم `/marry divorce` أولاً.', ephemeral: true });

      const partnerMarriage = getMarriage(partner.id);
      if (partnerMarriage) return interaction.reply({ content: '❌ هذا الشخص متزوج بالفعل!', ephemeral: true });

      const player = getPlayer(interaction.user.id, interaction.user.username);

      // Ring check - must have a ring
      const inv = require('../../database/db').getInventory(interaction.user.id);
      const ring = inv.find(i => i.item_name === 'خاتم الزواج');
      if (!ring) {
        return interaction.reply({ content: '❌ تحتاج **خاتم زواج** لطلب الزواج! اصنعه باستخدام `/craft` (الوصفة: جوهر الظلام ×1 + دمعة العنقاء ×2 + بلورة الطاقة ×3)', ephemeral: true });
      }

      const embed = createBaseEmbed('💍 طلب زواج',
        `**${interaction.user.username}** يتقدم لخطبة **${partner.username}** 💕\n\n` +
        `❤️ هل تقبل به زوجاً/زوجةً لك في عالم الظل؟\n\n` +
        `على ${partner.username} الرد خلال 60 ثانية`,
        0xff69b4
      );

      const row = new ActionRowBuilder()
        .addComponents(
          new ButtonBuilder().setCustomId(`marry_accept:${interaction.user.id}`).setLabel('💍 أقبل').setStyle(ButtonStyle.Success),
          new ButtonBuilder().setCustomId(`marry_decline:${interaction.user.id}`).setLabel('❌ أرفض').setStyle(ButtonStyle.Danger)
        );

      await interaction.reply({ embeds: [embed], components: [row] });

      // Handle response
      const filter = i => i.customId.startsWith('marry_') && i.user.id === partner.id;
      try {
        const response = await interaction.channel.awaitMessageComponent({ filter, time: 60000 });

        if (response.customId === 'marry_decline') {
          const declineEmbed = createBaseEmbed('💔 رفض', `${partner.username} رفض الزواج من ${interaction.user.username}... 😢`, 0x888888);
          await response.update({ embeds: [declineEmbed], components: [] });
          return;
        }

        // Accept - remove ring and marry
        const { removeItem } = require('../../database/db');
        removeItem(ring.id);

        marryUsers(interaction.user.id, partner.id);
        checkAchievements(interaction.user.id);
        checkAchievements(partner.id);

        const acceptEmbed = createBaseEmbed('💑 **مبروك الزواج!** 🎉',
          `**${interaction.user.username}** ❤️ **${partner.username}**\n\n` +
          `أصبحتما متزوجين في عالم ممالك الظل!\n` +
          `بارك الله لكما وبارك عليكما وجمع بينكما في الخير 🤲\n\n` +
          `💍 تم استخدام خاتم الزواج`,
          0xff69b4
        );
        await response.update({ embeds: [acceptEmbed], components: [] });

      } catch (e) {
        const timeoutEmbed = createBaseEmbed('⏰ انتهى الوقت', `${partner.username} لم يرد على طلب الزواج.`, 0x888888);
        await interaction.editReply({ embeds: [timeoutEmbed], components: [] });
      }

    } else if (sub === 'accept') {
      const partner = interaction.options.getUser('partner');
      // This would be handled by the propose flow
      return interaction.reply({ content: '📌 استخدم عندما يرسل لك شخص طلب زواج عبر `/marry propose`.', ephemeral: true });

    } else if (sub === 'info') {
      const marriage = getMarriage(interaction.user.id);
      if (!marriage) return interaction.reply({ content: '❌ أنت غير متزوج! استخدم `/marry propose`.', ephemeral: true });

      const p1 = getQuery('SELECT username FROM players WHERE user_id = ?', [marriage.user1_id]);
      const p2 = getQuery('SELECT username FROM players WHERE user_id = ?', [marriage.user2_id]);
      const otherId = marriage.user1_id === interaction.user.id ? marriage.user2_id : marriage.user1_id;
      const otherName = marriage.user1_id === interaction.user.id ? p2?.username : p1?.username;

      const embed = createBaseEmbed('💑 الزواج', 
        `**${interaction.user.username}** 💕 **${otherName}**\n\n` +
        `📅 تزوجتما في: ${marriage.married_at}\n` +
        `💍 الزوج: <@${marriage.user1_id}>\n` +
        `💍 الزوجة: <@${marriage.user2_id}>`,
        0xff69b4
      );
      await interaction.reply({ embeds: [embed] });

    } else if (sub === 'divorce') {
      const marriage = getMarriage(interaction.user.id);
      if (!marriage) return interaction.reply({ content: '❌ أنت غير متزوج!', ephemeral: true });

      const result = divorceUsers(interaction.user.id);
      if (!result) return interaction.reply({ content: '❌ حدث خطأ!', ephemeral: true });

      const embed = createBaseEmbed('💔 طلاق', `تم الطلاق. انفصلتما في عالم الظل... 😢`, 0x888888);
      await interaction.reply({ embeds: [embed] });
    }
  }
};

const { SlashCommandBuilder } = require('discord.js');
const { getPlayer, updatePlayer, getSkills, addItem, runQuery } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { doFishing, randomInt, checkCooldown, formatTime } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('fish')
    .setDescription('🎣 الصيد - اصطد في بحيرات الظل للحصول على الكنوز'),

  async execute(interaction) {
    const player = getPlayer(interaction.user.id, interaction.user.username);
    const cd = checkCooldown(interaction.user.id, 'fish', 5);

    if (cd.onCooldown) {
      return interaction.reply({ content: `⏳ انتظر ${formatTime(cd.remaining)} قبل الصيد مرة أخرى.`, ephemeral: true });
    }

    if (player.energy < 5) {
      return interaction.reply({ content: `❌ تحتاج 5 طاقة للصيد! طاقتك: ${player.energy}/${player.max_energy}`, ephemeral: true });
    }

    const skills = getSkills(interaction.user.id);
    const fishingLevel = skills.fishing_level || 1;

    updatePlayer(interaction.user.id, { energy: player.energy - 5 });

    const result = doFishing(fishingLevel);

    // XP gain for fishing skill
    const newFishingXp = (skills.fishing_xp || 0) + result.xpGain;
    const fishingXpNeeded = fishingLevel * 20;
    let newFishingLevel = fishingLevel;

    if (newFishingXp >= fishingXpNeeded) {
      newFishingLevel = fishingLevel + 1;
      runQuery('UPDATE player_skills SET fishing_level = ?, fishing_xp = ? WHERE user_id = ?', [newFishingLevel, newFishingXp - fishingXpNeeded, interaction.user.id]);
    } else {
      runQuery('UPDATE player_skills SET fishing_xp = ? WHERE user_id = ?', [newFishingXp, interaction.user.id]);
    }

    addItem(interaction.user.id, 'material', result.item.name, result.item.rarity, result.quantity);
    updatePlayer(interaction.user.id, { gold: player.gold + result.bonusGold });

    const xpGain = Math.floor(result.xpGain * 0.5);
    updatePlayer(interaction.user.id, { xp: player.xp + xpGain });

    const rarityEmojis = { 'شائع': '⬜', 'نادر': '🟦', 'أسطوري': '🟨', 'خرافي': '🟪' };

    const embed = createBaseEmbed('🎣 صيد',
      `🎣 ترمي صنارتك في مياه الظل...\n\n` +
      `🐟 اصطدت: ${rarityEmojis[result.item.rarity] || '⬜'} **${result.item.name}**\n` +
      `💰 ذهب إضافي: +${result.bonusGold}\n` +
      `📊 خبرة صيد: +${result.xpGain} (المستوى ${newFishingLevel})\n\n` +
      `⚡ طاقتك: ${player.energy - 5}/${player.max_energy}`,
      result.item.rarity === 'نادر' ? 0x00aaff : result.item.rarity === 'أسطوري' ? 0xffaa00 : result.item.rarity === 'خرافي' ? 0xff44ff : 0x888888
    );

    if (newFishingLevel > fishingLevel) {
      embed.addFields({ name: '🎉 ارتفاع مستوى الصيد!', value: `تهانينا! وصلت إلى مستوى صيد ${newFishingLevel}!`, inline: false });
    }

    await interaction.reply({ embeds: [embed] });
  }
};

