setInterval(() => {
  try {
    const { getActiveWorldBoss, spawnWorldBoss } = require('./database/db');
    const active = getActiveWorldBoss();
    if (!active) {
      // 30% chance to spawn a new boss every 10 min
      if (Math.random() < 0.3) {
        const boss = spawnWorldBoss();
        if (boss) {
          console.log(chalk.magenta(`[WORLD BOSS] 🐉 ${boss.name} ظهر في عالم الظل!`));
          // Announce in first guild
          const guild = client.guilds.cache.first();
          if (guild) {
            const channel = guild.systemChannel || guild.channels.cache.find(c => c.type === 0);
            if (channel) {
              const { createBaseEmbed } = require('./utils/embeds');
              const embed = createBaseEmbed('🐉 **بوس عالمي جديد!**',
                `**${boss.name}** ظهر في عالم الظل!\n` +
                `❤️ HP: ${boss.hp.toLocaleString()}\n` +
                `💰 الجائزة: ${boss.reward_pool.toLocaleString()} ذهب\n\n` +
                `🎯 استخدم \`/boss\` للمشاركة!`,
                0xff0000
              );
              channel.send({ embeds: [embed] }).catch(() => {});
            }
          }
        }
      }
    }
  } catch (e) {
    console.error(chalk.red(`[WORLD BOSS] ✗ ${e.message}`));
  }
}, 10 * 60 * 1000);

