    const winner = drawLottery();
    if (winner) {
      const totalTickets = allQuery('SELECT COUNT(*) as count FROM lottery_tickets');
      const prize = Math.floor((totalTickets?.[0]?.count || 0) * 500 * 1.5);

      updatePlayer(winner.user_id, {
        gold: (getQuery('SELECT gold FROM players WHERE user_id = ?', [winner.user_id])?.gold || 0) + prize
      });

      console.log(chalk.yellow(`[LOTTERY] 🍀 ${winner.username} ربح اليانصيب! ${prize}💰`));

      const guild = client.guilds.cache.first();
      if (guild) {
        const channel = guild.systemChannel || guild.channels.cache.find(c => c.type === 0);
        if (channel) {
          const { createBaseEmbed } = require('./utils/embeds');
          const playerData = getQuery('SELECT * FROM players WHERE user_id = ?', [winner.user_id]);
          const embed = createBaseEmbed('🍀 **يانصيب الظل**',
            `🎉 **${playerData?.username || winner.user_id}** ربح اليانصيب!\n\n` +
            `💰 الجائزة: ${prize.toLocaleString()} ذهب!\n` +
            `${winner.ticket_number ? `🎟️ التذكرة: #${winner.ticket_number}` : ''}`,
            0xffd700
          );
          channel.send({ embeds: [embed] }).catch(() => {});
        }
      }
    }
  } catch (e) {
    console.error(chalk.red(`[LOTTERY] ✗ ${e.message}`));
  }
}, 60 * 60 * 1000);

// Handle unhandled errors
process.on('unhandledRejection', (error) => {
  console.error(chalk.red('❌ خطأ غير متوقع:'), error.message);
});

