const { SlashCommandBuilder } = require('discord.js');
const { getPlayer, updatePlayer, getInventory, addItem, removeItem, getActiveBoosters, activateBooster } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { randomInt } = require('../../utils/helpers');

const shopItems = require('../../utils/helpers').shopItems;

module.exports = {
  data: new SlashCommandBuilder()
    .setName('use')
    .setDescription('🧪 استخدام عنصر من مخزونك (جرعات، معززات، إلخ)')
    .addStringOption(option =>
      option.setName('item')
        .setDescription('اسم العنصر الذي تريد استخدامه')
        .setRequired(true)
        .setAutocomplete(true)
    ),

  async execute(interaction) {
    const itemName = interaction.options.getString('item');
    const player = getPlayer(interaction.user.id, interaction.user.username);
    const inventory = getInventory(interaction.user.id);

    const item = inventory.find(i => 
      i.item_name.toLowerCase() === itemName.toLowerCase() || 
      i.item_name.includes(itemName)
    );

    if (!item) {
      const embed = createBaseEmbed('❌ عنصر غير موجود', 'لم أجد هذا العنصر في مخزونك.', 0xff4444);
      return interaction.reply({ embeds: [embed], ephemeral: true });
    }

    // Handle different item types
    switch (item.item_type) {
      case 'potion': {
        const stats = typeof item.stats === 'string' ? JSON.parse(item.stats) : item.stats;

        if (stats.heal) {
          if (player.health >= player.max_health) {
            const embed = createBaseEmbed('❤️ صحة كاملة', 'صحتك كاملة بالفعل!', 0xffaa00);
            return interaction.reply({ embeds: [embed], ephemeral: true });
          }

          const newHealth = Math.min(player.health + stats.heal, player.max_health);
          const actualHeal = newHealth - player.health;
          updatePlayer(interaction.user.id, { health: newHealth });
          removeItem(item.id);

          const embed = createBaseEmbed('🧪 استخدام جرعة',
            `**${item.item_name}**\n\n` +
            `💚 استعدت **${actualHeal}** نقطة صحة\n` +
            `❤️ صحتك الآن: ${newHealth}/${player.max_health}`,
            0x00ff88
          );
          return interaction.reply({ embeds: [embed] });
        }

        if (stats.fullHeal) {
          if (player.health >= player.max_health) {
            const embed = createBaseEmbed('❤️ صحة كاملة', 'صحتك كاملة بالفعل!', 0xffaa00);
            return interaction.reply({ embeds: [embed], ephemeral: true });
          }

          const oldHealth = player.health;
          updatePlayer(interaction.user.id, { health: player.max_health });
          removeItem(item.id);

          const embed = createBaseEmbed('🧪 جرعة إعادة الصحة الكلية',
            `**${item.item_name}**\n\n` +
            `💚 شفيت بالكامل!\n` +
            `❤️ ${oldHealth} → ${player.max_health}`,
            0x00ff88
          );
          return interaction.reply({ embeds: [embed] });
        }

        if (stats.energy) {
          if (player.energy >= player.max_energy) {
            const embed = createBaseEmbed('⚡ طاقة كاملة', 'طاقتك كاملة بالفعل!', 0xffaa00);
            return interaction.reply({ embeds: [embed], ephemeral: true });
          }

          const newEnergy = Math.min(player.energy + stats.energy, player.max_energy);
          const actualGain = newEnergy - player.energy;
          updatePlayer(interaction.user.id, { energy: newEnergy });
          removeItem(item.id);

          const embed = createBaseEmbed('⚡ جرعة طاقة',
            `**${item.item_name}**\n\n` +
            `⚡ استعدت **${actualGain}** طاقة\n` +
            `⚡ طاقتك الآن: ${newEnergy}/${player.max_energy}`,
            0x00aaff
          );
          return interaction.reply({ embeds: [embed] });
        }

        if (stats.attackBoost) {
          const existingBoosters = getActiveBoosters(interaction.user.id);
          const hasAttackBooster = existingBoosters.some(b => b.booster_type === 'attackBoost');
          if (hasAttackBooster) {
            return interaction.reply({ content: '❌ لديك بالفعل معزز هجوم نشط!', ephemeral: true });
          }

          activateBooster(interaction.user.id, 'attackBoost', 1.0, stats.duration || 300);
          removeItem(item.id);

          const embed = createBaseEmbed('⚔️ معزز هجوم',
            `**${item.item_name}**\n\n` +
            `⚔️ هجومك معزز لمدة ${(stats.duration || 300) / 60} دقائق!\n` +
            `💥 +${stats.attackBoost} هجوم إضافي`,
            0xff6600
          );
          return interaction.reply({ embeds: [embed] });
        }

        if (stats.luckBoost) {
          const existingBoosters = getActiveBoosters(interaction.user.id);
          const hasLuckBooster = existingBoosters.some(b => b.booster_type === 'luck');
          if (hasLuckBooster) {
            return interaction.reply({ content: '❌ لديك بالفعل معزز حظ نشط!', ephemeral: true });
          }

          activateBooster(interaction.user.id, 'luck', 2.0, stats.duration || 600);
          removeItem(item.id);

          const embed = createBaseEmbed('🍀 معزز حظ',
            `**${item.item_name}**\n\n` +
            `🍀 حظك معزز لمدة ${(stats.duration || 600) / 60} دقائق!\n` +
            `✨ حظ إضافي: +${stats.luckBoost}`,
            0x44ff44
          );
          return interaction.reply({ embeds: [embed] });
        }

        if (stats.maxHpBoost) {
          updatePlayer(interaction.user.id, {
            max_health: player.max_health + (stats.maxHpBoost || 0),
            health: player.health + (stats.maxHpBoost || 0)
          });
          removeItem(item.id);

          const embed = createBaseEmbed('❤️ تعزيز الصحة القصوى',
            `**${item.item_name}**\n\n` +
            `❤️ زادت صحتك القصوى بمقدار ${stats.maxHpBoost || 0}!\n` +
            `❤️ ${player.max_health} → ${player.max_health + (stats.maxHpBoost || 0)}`,
            0xff4488
          );
          return interaction.reply({ embeds: [embed] });
        }

        break;
      }

      case 'essence': {
        const stats = typeof item.stats === 'string' ? JSON.parse(item.stats) : item.stats;
        const essenceAmount = stats.essence || 0;

        updatePlayer(interaction.user.id, {
          shadow_essence: (player.shadow_essence || 0) + essenceAmount
        });
        removeItem(item.id);

        const embed = createBaseEmbed('💎 جوهر الظل',
          `**${item.item_name}**\n\n` +
          `💎 حصلت على **${essenceAmount}** جوهر ظل!\n` +
          `💎 الإجمالي: ${(player.shadow_essence || 0) + essenceAmount}`,
          0xaa44ff
        );
        return interaction.reply({ embeds: [embed] });
      }

      case 'booster': {
        const stats = typeof item.stats === 'string' ? JSON.parse(item.stats) : item.stats;
        const existingBoosters = getActiveBoosters(interaction.user.id);
        const hasSameType = existingBoosters.some(b => b.booster_type === stats.type);

        if (hasSameType) {
          return interaction.reply({ content: '❌ لديك بالفعل معزز نشط من هذا النوع!', ephemeral: true });
        }

        activateBooster(interaction.user.id, stats.type, stats.multiplier || 1.5, stats.duration || 30);
        removeItem(item.id);

        const typeNames = { xp: 'الخبرة 📊', gold: 'الذهب 💰', luck: 'الحظ 🍀', all: 'الكل 🌟' };
        const embed = createBaseEmbed('⚡ معزز',
          `**${item.item_name}**\n\n` +
          `⚡ تم تفعيل معزز **${typeNames[stats.type] || stats.type}**!\n` +
          `🔄 ×${stats.multiplier || 1.5} لمدة ${stats.duration || 30} دقيقة`,
          stats.type === 'xp' ? 0x00aaff : stats.type === 'gold' ? 0xffd700 : 0x44ff44
        );
        return interaction.reply({ embeds: [embed] });
      }

      case 'weapon':
      case 'armor': {
        // Toggle equipment
        const inventory2 = getInventory(interaction.user.id);
        const currentEquipped = inventory2.find(i => i.item_type === item.item_type && i.equipped === 1);

        if (currentEquipped && currentEquipped.id === item.id) {
          // Unequip
          const { runQuery } = require('../../database/db');
          runQuery('UPDATE inventory SET equipped = 0 WHERE id = ?', [item.id]);

          // Remove stats
          const stats = typeof item.stats === 'string' ? JSON.parse(item.stats) : item.stats;
          updatePlayer(interaction.user.id, {
            attack: Math.max(1, player.attack - (stats.attack || 0)),
            defense: Math.max(0, player.defense - (stats.defense || 0)),
            max_health: Math.max(100, player.max_health - (stats.health || 0)),
            health: Math.max(50, player.health - (stats.health || 0))
          });

          const embed = createBaseEmbed('🔄 نزع العنصر',
            `**${item.item_name}** تم نزعه.\n` +
            `تم إزالة الإحصائيات.`,
            0x888888
          );
          return interaction.reply({ embeds: [embed] });
        } else {
          // Unequip previous
          if (currentEquipped) {
            const { runQuery } = require('../../database/db');
            runQuery('UPDATE inventory SET equipped = 0 WHERE id = ?', [currentEquipped.id]);

            const oldStats = typeof currentEquipped.stats === 'string' ? JSON.parse(currentEquipped.stats) : currentEquipped.stats;
            updatePlayer(interaction.user.id, {
              attack: Math.max(1, player.attack - (oldStats.attack || 0)),
              defense: Math.max(0, player.defense - (oldStats.defense || 0)),
              max_health: Math.max(100, player.max_health - (oldStats.health || 0)),
              health: Math.max(50, player.health - (oldStats.health || 0))
            });
          }

          // Equip new
          const { runQuery } = require('../../database/db');
          runQuery('UPDATE inventory SET equipped = 1 WHERE id = ?', [item.id]);

          const stats = typeof item.stats === 'string' ? JSON.parse(item.stats) : item.stats;
          updatePlayer(interaction.user.id, {
            attack: player.attack + (stats.attack || 0),
            defense: player.defense + (stats.defense || 0),
            max_health: player.max_health + (stats.health || 0),
            health: player.health + (stats.health || 0)
          });

          const typeName = item.item_type === 'weapon' ? 'سلاح' : 'درع';
          const embed = createBaseEmbed(`✅ تجهيز ${typeName}`,
            `**${item.item_name}** مجهز الآن!\n\n` +
            `⚔️ هجوم: +${stats.attack || 0}\n` +
            `🛡️ دفاع: +${stats.defense || 0}\n` +
            `❤️ صحة إضافية: +${stats.health || 0}`,
            0x00ff88
          );
          return interaction.reply({ embeds: [embed] });
        }
      }

      default:
        break;
    }

    const embed = createBaseEmbed('❌ لا يمكن الاستخدام', 
      `**${item.item_name}** من نوع ${item.item_type} لا يمكن استخدامه مباشرة.\n` +
      `بعض العناصر تُستخدم تلقائياً أو عبر أوامر أخرى.`,
      0xff4444
    );
    await interaction.reply({ embeds: [embed], ephemeral: true });
  }
};

const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer, getInventory, addItem, removeItem } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');

const activeGifts = new Map();

module.exports = {
  data: new SlashCommandBuilder()
    .setName('gift')
    .setDescription('🎁 إرسال هدية إلى لاعب آخر (ذهب أو عناصر)')
    .addUserOption(option =>
      option.setName('recipient')
        .setDescription('اللاعب المستلم')
        .setRequired(true)
    )
    .addIntegerOption(option =>
      option.setName('gold')
        .setDescription('كمية الذهب')
        .setRequired(false)
        .setMinValue(1)
    )
    .addStringOption(option =>
      option.setName('item')
        .setDescription('اسم العنصر (اختياري)')
        .setRequired(false)
        .setAutocomplete(true)
    )
    .addIntegerOption(option =>
      option.setName('quantity')
        .setDescription('الكمية (افتراضي: 1)')
        .setRequired(false)
        .setMinValue(1)
        .setMaxValue(99)
    ),

  async execute(interaction) {
    const recipient = interaction.options.getUser('recipient');
    const gold = interaction.options.getInteger('gold') || 0;
    const itemName = interaction.options.getString('item');
    const quantity = interaction.options.getInteger('quantity') || 1;

    if (recipient.id === interaction.user.id) {
      return interaction.reply({ content: '❌ لا يمكنك إرسال هدية لنفسك!', ephemeral: true });
    }

    if (recipient.bot) {
      return interaction.reply({ content: '❌ لا يمكنك إرسال هدايا للبوتات!', ephemeral: true });
    }

    if (gold <= 0 && !itemName) {
      return interaction.reply({ content: '❌ يجب تحديد ذهب أو عنصر على الأقل!', ephemeral: true });
    }

    const sender = getPlayer(interaction.user.id, interaction.user.username);

    // Validate gold
    if (gold > 0 && sender.gold < gold) {
      return interaction.reply({ content: `❌ ليس لديك ${gold} ذهب! رصيدك: ${sender.gold}`, ephemeral: true });
    }

    // Validate item
    let item = null;
    if (itemName) {
      const inventory = getInventory(interaction.user.id);
      item = inventory.find(i => 
        i.item_name.toLowerCase() === itemName.toLowerCase() || 
        i.item_name.includes(itemName)
      );

      if (!item) {
        return interaction.reply({ content: `❌ لم أجد العنصر "${itemName}" في مخزونك!`, ephemeral: true });
      }

      if (item.quantity < quantity) {
        return interaction.reply({ content: `❌ لديك فقط ${item.quantity} من "${item.item_name}"!`, ephemeral: true });
      }

      if (item.equipped) {
        return interaction.reply({ content: '❌ لا يمكن إهداء عنصر مجهز! انزعه أولاً باستخدام `/use`.', ephemeral: true });
      }
    }

    // Check for active gift
    if (activeGifts.has(interaction.user.id) || activeGifts.has(recipient.id)) {
      return interaction.reply({ content: '❌ لديك already طلب هدية نشط!', ephemeral: true });
    }

    const giftId = `${interaction.user.id}-${recipient.id}-${Date.now()}`;
    activeGifts.set(interaction.user.id, giftId);
    activeGifts.set(recipient.id, giftId);

    const embed = createBaseEmbed('🎁 هدية',
      `**${interaction.user.username}** يريد إرسال هدية إلى **${recipient.username}**!\n\n` +
      `${gold > 0 ? `💰 **الذهب:** ${gold.toLocaleString()}\n` : ''}` +
      `${item ? `📦 **العنصر:** ${item.item_name} ×${quantity} (${item.item_rarity})\n` : ''}` +
      `\nعلى ${recipient.username} الرد خلال 60 ثانية`,
      0xff69b4
    );

    const row = new ActionRowBuilder()
      .addComponents(
        new ButtonBuilder()
          .setCustomId(`gift_accept:${interaction.user.id}:${gold}:${item ? item.id : 0}:${quantity}`)
          .setLabel('✅ قبول')
          .setStyle(ButtonStyle.Success),
        new ButtonBuilder()
          .setCustomId(`gift_decline:${interaction.user.id}`)
          .setLabel('❌ رفض')
          .setStyle(ButtonStyle.Danger)
      );

    await interaction.reply({ embeds: [embed], components: [row] });

    setTimeout(() => {
      activeGifts.delete(interaction.user.id);
      activeGifts.delete(recipient.id);
    }, 60000);
  }
};

