async function handleDuelAccept(interaction, args) {
  const { getPlayer, updatePlayer } = require('../database/db');
  const { calculateDamage, randomInt } = require('../utils/helpers');
  const { createBaseEmbed } = require('../utils/embeds');

  const challengerId = args[0];
  const bet = parseInt(args[1]) || 0;

  if (interaction.user.id !== interaction.user.id) return; // Safety
  if (challengerId === interaction.user.id) {
    return interaction.reply({ content: '❌ لا يمكنك قبول مبارزتك الخاصة!', ephemeral: true });
  }

  const defender = getPlayer(interaction.user.id, interaction.user.username);
  const challenger = getPlayer(challengerId, '');

  if (!challenger) {
    return interaction.reply({ content: '❌ اللاعب المتحدي غير موجود!', ephemeral: true });
  }

  if (bet > 0) {
    if (defender.gold < bet) {
      return interaction.reply({ content: `❌ ليس لديك ${bet} ذهب للمراهنة!`, ephemeral: true });
    }
    // Check challenger still has gold
    const freshChallenger = getPlayer(challengerId, '');
    if (freshChallenger.gold < bet) {
      return interaction.reply({ content: `❌ ${freshChallenger.username} لم يعد لديه ${bet} ذهب!`, ephemeral: true });
    }
  }

  // Simulate duel
  const attackerPower = challenger.attack + challenger.level * 2 + randomInt(1, 20);
  const defenderPower = defender.attack + defender.level * 2 + randomInt(1, 20);

  const attackerWon = attackerPower > defenderPower;
  const winner = attackerWon ? challenger : defender;
  const loser = attackerWon ? defender : challenger;

  let log = `🤺 **مبارزة شرف!**\n\n`;
  log += `⚔️ **${challenger.username}** (HP: ${challenger.health}) ⚔️ **${defender.username}** (HP: ${defender.health})\n\n`;

  // Exchange blows
  const cDmg = calculateDamage(challenger.attack, defender.defense, challenger.luck || 5, challenger.crit_chance || 5, challenger.crit_damage || 150, challenger.dodge_chance || 5);
  const dDmg = calculateDamage(defender.attack, challenger.defense, defender.luck || 5, defender.crit_chance || 5, defender.crit_damage || 150, defender.dodge_chance || 5);

  log += `⚔️ ${challenger.username} يوجه ضربة ${cDmg.isCrit ? 'حرجة 💥' : ''} ${cDmg.damage} ضرر!\n`;
  log += `⚔️ ${defender.username} يرد بـ ${dDmg.isCrit ? 'حرجة 💥' : ''} ${dDmg.damage} ضرر!\n\n`;

  if (attackerWon) {
    log += `🎉 **${challenger.username} انتصر!**\n`;
  } else {
    log += `🎉 **${defender.username} انتصر!**\n`;
  }

  // Process rewards
  const xpReward = randomInt(20, 50) + winner.level * 2;
  updatePlayer(winner.user_id, { xp: winner.xp + xpReward });
  updatePlayer(loser.user_id, { xp: loser.xp + Math.floor(xpReward * 0.3) });

  if (bet > 0) {
    updatePlayer(winner.user_id, { gold: winner.gold + bet });
    updatePlayer(loser.user_id, { gold: loser.gold - bet });
    log += `\n💰 ${winner.username} ربح ${bet} ذهب من الرهان!`;
  }

  log += `\n📊 ${winner.username} حصل على ${xpReward} XP`;

  const embed = createBaseEmbed('🤺 نتيجة المبارزة', log, attackerWon ? 0x00ff88 : 0xff4444);

  const { updatePlayer: updateDef } = require('../database/db'); // refresh
  await interaction.update({ embeds: [embed], components: [] });

  // Clean up active duels
  try {
    const duelMap = require('../commands/battle/duel').activeDuels;
    if (duelMap) {
      duelMap.delete(challengerId);
      duelMap.delete(interaction.user.id);
    }
  } catch (e) {}
}

