  const { getPlayer, updatePlayer, getInventory, removeItem } = require('../database/db');
  const { createBaseEmbed } = require('../utils/embeds');
  const { chance, randomInt } = require('../utils/helpers');

  const itemId = parseInt(args[0]);
  const essenceCost = parseInt(args[1]);
  const goldCost = parseInt(args[2]);
  const successChance = parseInt(args[3]);

  const player = getPlayer(interaction.user.id, interaction.user.username);
  const inventory = getInventory(interaction.user.id);
  const item = inventory.find(i => i.id === itemId);

  if (!item) {
    return interaction.reply({ content: '❌ العنصر غير موجود في مخزونك!', ephemeral: true });
  }

  if ((player.shadow_essence || 0) < essenceCost || player.gold < goldCost) {
    return interaction.reply({ content: '❌ ليس لديك الموارد الكافية!', ephemeral: true });
  }

  // Deduct costs
  updatePlayer(interaction.user.id, {
    shadow_essence: (player.shadow_essence || 0) - essenceCost,
    gold: player.gold - goldCost
  });

  const success = chance(successChance);

  if (success) {
    // Upgrade rarity
    const rarityOrder = ['شائع', 'نادر', 'أسطوري', 'خرافي'];
    const currentIdx = rarityOrder.indexOf(item.item_rarity);
    if (currentIdx < rarityOrder.length - 1) {
      const { runQuery } = require('../database/db');
      runQuery('UPDATE inventory SET item_rarity = ? WHERE id = ?', [rarityOrder[currentIdx + 1], item.id]);

      const embed = createBaseEmbed('✅ **تطوير ناجح!**',
        `**${item.item_name}** ⬆️ ${rarityOrder[currentIdx + 1]}\n\n` +
        `🎉 تم تطوير العنصر بنجاح!\n` +
        `⭐ ${item.item_rarity} → **${rarityOrder[currentIdx + 1]}**`,
        0xffd700
      );
      await interaction.update({ embeds: [embed], components: [] });
    } else {
      // Already max rarity, boost stats instead
      const stats = typeof item.stats === 'string' ? JSON.parse(item.stats) : item.stats;
      const newStats = {};
      for (const [k, v] of Object.entries(stats)) {
        newStats[k] = Math.floor(v * 1.2);
      }
      const { runQuery } = require('../database/db');
      runQuery('UPDATE inventory SET stats = ? WHERE id = ?', [JSON.stringify(newStats), item.id]);

      const embed = createBaseEmbed('✅ **تعزيز ناجح!**',
        `**${item.item_name}** ⬆️ إحصائيات معززة!\n\n` +
        `🎉 تم تعزيز إحصائيات العنصر بنسبة 20%!`,
        0xffd700
      );
      await interaction.update({ embeds: [embed], components: [] });
    }
  } else {
    const embed = createBaseEmbed('❌ **فشل التطوير!**',
      `**${item.item_name}**\n\n` +
      `💔 فشلت عملية التطوير...\n` +
      `💎 خسرت ${essenceCost} جوهر ظل\n` +
      `💰 خسرت ${goldCost} ذهب`,
      0xff4444
    );
    await interaction.update({ embeds: [embed], components: [] });
  }
}

