// ====== GIFT HANDLERS ======

async function handleGiftAccept(interaction, args) {
  const { getPlayer, updatePlayer, getInventory, addItem, removeItem } = require('../database/db');
  const { createBaseEmbed } = require('../utils/embeds');

  const senderId = args[0];
  const gold = parseInt(args[1]);
  const itemId = parseInt(args[2]);
  const quantity = parseInt(args[3]);

  if (interaction.user.id === senderId) {
    return interaction.reply({ content: '❌ لا يمكنك قبول هديتك الخاصة!', ephemeral: true });
  }

  const sender = getPlayer(senderId, '');
  const receiver = getPlayer(interaction.user.id, interaction.user.username);

  if (!sender) {
    return interaction.reply({ content: '❌ المرسل غير موجود!', ephemeral: true });
  }

  // Process gold
  if (gold > 0) {
    if (sender.gold < gold) {
      return interaction.reply({ content: `❌ ${sender.username} لم يعد لديه ${gold} ذهب!`, ephemeral: true });
    }
    updatePlayer(senderId, { gold: sender.gold - gold });
    updatePlayer(interaction.user.id, { gold: receiver.gold + gold });
  }

  // Process item
  let itemName = '';
  let itemRarity = '';
  if (itemId > 0) {
    const senderInv = getInventory(senderId);
    const item = senderInv.find(i => i.id === itemId);
    if (!item || item.quantity < quantity) {
      return interaction.reply({ content: `❌ ${sender.username} لم يعد لديه هذا العنصر!`, ephemeral: true });
    }
    itemName = item.item_name;
    itemRarity = item.item_rarity;
    removeItem(item.id, quantity);
    addItem(interaction.user.id, item.item_type, item.item_name, item.item_rarity, quantity, item.stats);
  }

  const desc = `🎁 **${sender.username}** أرسل هدية إلى **${interaction.user.username}**!\n\n` +
    `${gold > 0 ? `💰 **الذهب:** ${gold.toLocaleString()}\n` : ''}` +
    `${itemName ? `📦 **العنصر:** ${itemName} ×${quantity} (${itemRarity})` : ''}`;

  const embed = createBaseEmbed('🎁 تم استلام الهدية!', desc, 0xff69b4);
  await interaction.update({ embeds: [embed], components: [] });

  // Clean up
  try {
    const giftMap = require('../commands/social/gift').activeGifts;
    if (giftMap) {
      giftMap.delete(senderId);
      giftMap.delete(interaction.user.id);
    }
  } catch (e) {}
}

