async function handleArenaFight(interaction, args) {
  const { getPlayer, updatePlayer, getQuery, runQuery, checkAchievements } = require('../database/db');
  const { calculateDamage, randomInt, chance } = require('../utils/helpers');
  const { createBaseEmbed } = require('../utils/embeds');

  const player = getPlayer(interaction.user.id, interaction.user.username);
  const opponentIndex = parseInt(args[0]);

  const arenaOpponents = [
    { name: 'فارس الظل المبتدئ', level: Math.max(1, player.level - 1), hp: 80 + player.level * 5, attack: 8 + player.level * 2, defense: 4 + player.level, reward: 100 + player.level * 20 },
    { name: 'محارب القبيلة', level: player.level, hp: 100 + player.level * 8, attack: 10 + player.level * 3, defense: 5 + player.level * 1.5, reward: 200 + player.level * 30 },
    { name: 'حارس العتمة', level: player.level + 1, hp: 120 + player.level * 10, attack: 12 + player.level * 4, defense: 6 + player.level * 2, reward: 350 + player.level * 40 },
    { name: 'ساحر الظلال الأسود', level: player.level + 2, hp: 90 + player.level * 12, attack: 18 + player.level * 4, defense: 3 + player.level, reward: 500 + player.level * 50 },
    { name: 'زعيم عشيرة الظل', level: player.level + 3, hp: 150 + player.level * 15, attack: 15 + player.level * 5, defense: 10 + player.level * 3, reward: 800 + player.level * 60 },
    { name: 'تنين الظل الأبدي', level: player.level + 5, hp: 200 + player.level * 20, attack: 20 + player.level * 6, defense: 15 + player.level * 4, reward: 1500 + player.level * 100 }
  ];

  const opponent = arenaOpponents[opponentIndex];
  if (!opponent) {
    return interaction.reply({ content: '❌ خصم غير صحيح!', ephemeral: true });
  }

  if (player.energy < 25) {
    return interaction.reply({ content: `❌ تحتاج 25 طاقة! طاقتك: ${player.energy}`, ephemeral: true });
  }

  updatePlayer(interaction.user.id, { energy: player.energy - 25 });

  // Fight simulation
  let playerHp = player.health;
  let enemyHp = opponent.hp;
  let log = `🏟️ **${interaction.user.username}** ⚔️ **${opponent.name}**\n\n`;

  let turns = 0;
  while (playerHp > 0 && enemyHp > 0 && turns < 30) {
    turns++;

    // Player attacks
    const pAtk = calculateDamage(player.attack, opponent.defense, player.luck || 5, player.crit_chance || 5, player.crit_damage || 150, player.dodge_chance || 5);
    if (pAtk.isDodged) {
      log += `💨 ${opponent.name} تفادى!\n`;
    } else {
      enemyHp -= pAtk.damage;
      log += `${pAtk.isCrit ? '💥 حرجة! ' : ''}⚔️ ${pAtk.damage} ضرر للمنافس\n`;
    }

    if (enemyHp <= 0) break;

    // Enemy attacks
    const eAtk = calculateDamage(opponent.attack, player.defense, 5, 5, 150, player.dodge_chance || 5);
    if (eAtk.isDodged) {
      log += `💨 تفاديت!\n`;
    } else {
      playerHp -= eAtk.damage;
      log += `💥 ${eAtk.damage} ضرر عليك\n`;
    }
  }

  const won = enemyHp <= 0;

  if (won) {
    const goldReward = opponent.reward + randomInt(0, 50);
    const xpReward = 50 + opponent.level * 10 + randomInt(0, 30);

    updatePlayer(interaction.user.id, {
      gold: player.gold + goldReward,
      xp: player.xp + xpReward,
      health: Math.max(1, playerHp)
    });

    // Level up check
    const { xpForLevel } = require('../utils/helpers');
    if (player.xp + xpReward >= xpForLevel(player.level)) {
      updatePlayer(interaction.user.id, {
        level: player.level + 1,
        xp: (player.xp + xpReward) - xpForLevel(player.level),
        max_health: player.max_health + 10,
        health: player.max_health + 10,
        attack: player.attack + 2,
        defense: player.defense + 1,
        max_energy: player.max_energy + 5
      });
      log += `\n🎉 **ارتقيت إلى المستوى ${player.level + 1}!**\n`;
    }

    // Check achievements
    checkAchievements(interaction.user.id);

    log += `\n🏆 **انتصار عظيم!**\n`;
    log += `💰 +${goldReward} ذهب\n`;
    log += `📊 +${xpReward} XP\n`;

    // Random loot
    if (chance(20)) {
      const { addItem } = require('../database/db');
      const loots = ['رمز النصر', 'شظية مجد', 'نجمة الشجاعة', 'تاج الغبار'];
      const loot = loots[Math.floor(Math.random() * loots.length)];
      addItem(interaction.user.id, 'material', loot, 'نادر');
      log += `🎁 +**${loot}**!\n`;
    }
  } else {
    const lostGold = Math.min(player.gold, Math.floor(opponent.reward * 0.2));
    updatePlayer(interaction.user.id, {
      gold: Math.max(0, player.gold - lostGold),
      health: 1
    });

    log += `\n💀 **هزيمة!** خسرت ${lostGold} ذهب...\n`;
  }

  log += `\n❤️ صحتك: ${won ? '✅' : playerHp}/${player.max_health}`;

  const embed = createBaseEmbed(`🏟️ ساحة القتال - ${opponent.name}`,
    log,
    won ? 0x00ff88 : 0xff4444
  );

  await interaction.update({ embeds: [embed], components: [] });
}

const { SlashCommandBuilder, PermissionFlagsBits } = require('discord.js');
const { getPlayer, updatePlayer, getQuery, allQuery, runQuery, spawnWorldBoss, startEvent, getActiveEvent, drawLottery, saveDatabase } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('admin')
    .setDescription('⚙️ أوامر الأدمن لإدارة السيرفر (للمشرفين فقط)')
    .setDefaultMemberPermissions(PermissionFlagsBits.Administrator)
    .addSubcommand(sub =>
      sub.setName('give')
        .setDescription('إعطاء لاعب موارد')
        .addUserOption(o => o.setName('user').setDescription('اللاعب').setRequired(true))
        .addIntegerOption(o => o.setName('gold').setDescription('الذهب').setRequired(false))
        .addIntegerOption(o => o.setName('essence').setDescription('جوهر الظل').setRequired(false))
        .addIntegerOption(o => o.setName('xp').setDescription('الخبرة').setRequired(false)))
    .addSubcommand(sub =>
      sub.setName('spawn_boss')
        .setDescription('استدعاء بوس عالمي جديد'))
    .addSubcommand(sub =>
      sub.setName('event')
        .setDescription('بدء حدث في السيرفر')
        .addStringOption(o => o.setName('type').setDescription('نوع الحدث').setRequired(true)
          .addChoices(
            { name: 'ضعف الخبرة', value: 'double_xp' },
            { name: 'طفرة ذهب', value: 'gold_rush' },
            { name: 'غزو الظل', value: 'shadow_invasion' },
            { name: 'تعزيز الحظ', value: 'luck_boost' }
          ))
        .addIntegerOption(o => o.setName('duration').setDescription('المدة بالدقائق (افتراضي: 60)').setRequired(false).setMinValue(10).setMaxValue(1440)))
    .addSubcommand(sub =>
      sub.setName('end_event')
        .setDescription('إنهاء الحدث الحالي'))
    .addSubcommand(sub =>
      sub.setName('lottery_draw')
        .setDescription('سحب اليانصيب الآن'))
    .addSubcommand(sub =>
      sub.setName('set_level')
        .setDescription('تحديد مستوى لاعب')
        .addUserOption(o => o.setName('user').setDescription('اللاعب').setRequired(true))
        .addIntegerOption(o => o.setName('level').setDescription('المستوى').setRequired(true).setMinValue(1).setMaxValue(200)))
    .addSubcommand(sub =>
      sub.setName('reset_player')
        .setDescription('إعادة تعيين لاعب (حذف كل شيء)')
        .addUserOption(o => o.setName('user').setDescription('اللاعب').setRequired(true)))
    .addSubcommand(sub =>
      sub.setName('stats')
        .setDescription('عرض إحصائيات السيرفر')),

  async execute(interaction) {
    // Check if user has admin permissions
    if (!interaction.memberPermissions.has(PermissionFlagsBits.Administrator) && interaction.user.id !== interaction.guild?.ownerId) {
      return interaction.reply({ content: '❌ هذا الأمر للمشرفين فقط!', ephemeral: true });
    }

    const sub = interaction.options.getSubcommand();

    switch (sub) {
      case 'give': {
        const target = interaction.options.getUser('user');
        const gold = interaction.options.getInteger('gold') || 0;
        const essence = interaction.options.getInteger('essence') || 0;
        const xp = interaction.options.getInteger('xp') || 0;

        const player = getPlayer(target.id, target.username);

        if (gold > 0) updatePlayer(target.id, { gold: player.gold + gold });
        if (essence > 0) updatePlayer(target.id, { shadow_essence: (player.shadow_essence || 0) + essence });
        if (xp > 0) {
          const { xpForLevel } = require('../../utils/helpers');
          const newTotal = player.xp + xp;
          if (newTotal >= xpForLevel(player.level)) {
            updatePlayer(target.id, {
              xp: newTotal - xpForLevel(player.level),
              level: player.level + 1
            });
          } else {
            updatePlayer(target.id, { xp: newTotal });
          }
        }

        const embed = createBaseEmbed('✅ تم إعطاء الموارد',
          `**${target.username}**\n\n` +
          `${gold > 0 ? `💰 **الذهب:** +${gold.toLocaleString()}\n` : ''}` +
          `${essence > 0 ? `💎 **جوهر الظل:** +${essence}\n` : ''}` +
          `${xp > 0 ? `📊 **الخبرة:** +${xp}\n` : ''}`,
          0x00ff88
        );
        await interaction.reply({ embeds: [embed] });
        break;
      }

      case 'spawn_boss': {
        const boss = spawnWorldBoss();
        if (!boss) {
          return interaction.reply({ content: '❌ حدث خطأ في استدعاء البوس!', ephemeral: true });
        }

        const embed = createBaseEmbed('🐉 تم استدعاء بوس عالمي!',
          `**${boss.name}**\n\n` +
          `❤️ HP: ${boss.hp.toLocaleString()}\n` +
          `⚔️ هجوم: ${boss.attack}\n` +
          `🛡️ دفاع: ${boss.defense}\n` +
          `💰 الجائزة: ${boss.reward_pool.toLocaleString()} ذهب\n\n` +
          `🎯 استخدم \`/boss\` للمشاركة!`,
          0xff0000
        );
        await interaction.reply({ embeds: [embed] });
        break;
      }

      case 'event': {
        const type = interaction.options.getString('type');
        const duration = interaction.options.getInteger('duration') || 60;

        const existing = getActiveEvent();
        if (existing) {
          return interaction.reply({ content: `❌ هناك حدث نشط بالفعل: **${existing.event_type}**! أنهه أولاً.`, ephemeral: true });
        }

        startEvent(type, duration, interaction.user.username);

        const typeNames = { double_xp: '✨ ضعف الخبرة', gold_rush: '💰 طفرة ذهب', shadow_invasion: '🌑 غزو الظل', luck_boost: '🍀 تعزيز الحظ' };

        const embed = createBaseEmbed('🎉 **حدث جديد!**',
          `**${typeNames[type] || type}**\n\n` +
          `📅 المدة: ${duration} دقيقة\n` +
          `👑 بواسطة: ${interaction.user.username}\n\n` +
          `استفيدوا من الحدث قبل انتهائه!`,
          0xffaa00
        );
        await interaction.reply({ embeds: [embed] });
        break;
      }

      case 'end_event': {
        runQuery('UPDATE server_events SET active = 0 WHERE active = 1');
        const embed = createBaseEmbed('✅ تم إنهاء الحدث', 'تم إنهاء الحدث الحالي بنجاح.', 0x888888);
        await interaction.reply({ embeds: [embed] });
        break;
      }

      case 'lottery_draw': {
        const winner = drawLottery();
        if (!winner) {
          return interaction.reply({ content: '❌ لا توجد تذاكر يانصيب للسحب!', ephemeral: true });
        }

        const totalTickets = allQuery('SELECT COUNT(*) as count FROM lottery_tickets');
        const prize = Math.floor((totalTickets?.[0]?.count || 0) * 500 * 1.5);

        updatePlayer(winner.user_id, {
          gold: (getQuery('SELECT gold FROM players WHERE user_id = ?', [winner.user_id])?.gold || 0) + prize
        });

        const playerData = getQuery('SELECT * FROM players WHERE user_id = ?', [winner.user_id]);

        const embed = createBaseEmbed('🍀 **يانصيب الظل**',
          `🎉 **${playerData?.username || '???'}** ربح اليانصيب!\n\n` +
          `💰 الجائزة: ${prize.toLocaleString()} ذهب!`,
          0xffd700
        );
        await interaction.reply({ embeds: [embed] });
        break;
      }

      case 'set_level': {
        const target = interaction.options.getUser('user');
        const level = interaction.options.getInteger('level');

        updatePlayer(target.id, { level, xp: 0 });

        const embed = createBaseEmbed('✅ تم تحديث المستوى',
          `**${target.username}** → المستوى ${level}`,
          0x00ff88
        );
        await interaction.reply({ embeds: [embed] });
        break;
      }

      case 'reset_player': {
        const target = interaction.options.getUser('user');

        // Confirm
        const embed = createBaseEmbed('⚠️ تحذير: إعادة تعيين لاعب',
          `**${target.username}**\n\n` +
          `سيتم حذف جميع بيانات هذا اللاعب:\n` +
          `• ملف اللاعب\n` +
          `• المخزون\n` +
          `• مخلوقات الظل\n` +
          `• العضوية في القبائل\n` +
          `• الإنجازات والمهام\n` +
          `• الزواج\n` +
          `• كل شيء!\n\n` +
          `❗ هذا الإجراء لا يمكن التراجع عنه!`,
          0xff4444
        );

        const { ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
        const row = new ActionRowBuilder()
          .addComponents(
            new ButtonBuilder().setCustomId(`admin_reset_confirm:${target.id}`).setLabel('✅ تأكيد الحذف').setStyle(ButtonStyle.Danger),
            new ButtonBuilder().setCustomId('admin_reset_cancel').setLabel('❌ إلغاء').setStyle(ButtonStyle.Secondary)
          );

        await interaction.reply({ embeds: [embed], components: [row] });

        const filter = i => i.customId.startsWith('admin_reset_') && i.user.id === interaction.user.id;
        try {
          const response = await interaction.channel.awaitMessageComponent({ filter, time: 15000 });

          if (response.customId === 'admin_reset_cancel') {
            const cancelEmbed = createBaseEmbed('❌ ألغي', 'تم إلغاء إعادة التعيين.', 0x888888);
            await response.update({ embeds: [cancelEmbed], components: [] });
            return;
          }

          // Delete all player data
          const userId = args[1];
          runQuery('DELETE FROM players WHERE user_id = ?', [userId]);
          runQuery('DELETE FROM inventory WHERE user_id = ?', [userId]);
          runQuery('DELETE FROM shadows WHERE user_id = ?', [userId]);
          runQuery('DELETE FROM guild_members WHERE user_id = ?', [userId]);
          runQuery('DELETE FROM achievements WHERE user_id = ?', [userId]);
          runQuery('DELETE FROM quests WHERE user_id = ?', [userId]);
          runQuery('DELETE FROM player_skills WHERE user_id = ?', [userId]);
          runQuery('DELETE FROM dungeon_progress WHERE user_id = ?', [userId]);
          runQuery('DELETE FROM marriages WHERE user1_id = ? OR user2_id = ?', [userId, userId]);
          runQuery('DELETE FROM friends WHERE user_id = ? OR friend_id = ?', [userId, userId]);
          runQuery('DELETE FROM market_listings WHERE seller_id = ?', [userId]);
          runQuery('DELETE FROM daily_log WHERE user_id = ?', [userId]);
          runQuery('DELETE FROM boosters WHERE user_id = ?', [userId]);
          runQuery('DELETE FROM world_boss_damage WHERE user_id = ?', [userId]);

          const doneEmbed = createBaseEmbed('✅ تم إعادة التعيين',
            `تم حذف جميع بيانات **${target.username}** بنجاح.\n` +
            `يمكنه البدء من جديد باستخدام أي أمر.`,
            0x00ff88
          );
          await response.update({ embeds: [doneEmbed], components: [] });
        } catch (e) {
          if (e.code !== 'INTERACTION_COLLECTOR_ERROR') {
            await interaction.editReply({ content: '⏰ انتهى الوقت.', components: [] }).catch(() => {});
          }
        }
        break;
      }

      case 'stats': {
        const totalPlayers = getQuery('SELECT COUNT(*) as count FROM players');
        const totalGuilds = getQuery('SELECT COUNT(*) as count FROM guilds');
        const totalShadows = getQuery('SELECT COUNT(*) as count FROM shadows');
        const totalItems = getQuery('SELECT COUNT(*) as count FROM inventory');
        const totalGold = getQuery('SELECT SUM(gold) as total FROM players');
        const topPlayer = getQuery('SELECT username, level, prestige FROM players ORDER BY level DESC, prestige DESC LIMIT 1');
        const activeBoss = getQuery('SELECT * FROM world_boss WHERE active = 1 AND defeated = 0');

        const embed = createBaseEmbed('📊 إحصائيات السيرفر',
          `**🌑 ممالك الظل**\n\n` +
          `👤 **اللاعبين:** ${totalPlayers?.count || 0}\n` +
          `🏰 **القبائل:** ${totalGuilds?.count || 0}\n` +
          `👾 **مخلوقات الظل:** ${totalShadows?.count || 0}\n` +
          `📦 **العناصر:** ${totalItems?.count || 0}\n` +
          `💰 **إجمالي الذهب:** ${(totalGold?.total || 0).toLocaleString()}\n\n` +
          `🏆 **أقوى لاعب:** ${topPlayer ? `${topPlayer.username} (مستوى ${topPlayer.level}${topPlayer.prestige > 0 ? `, تمرير ${topPlayer.prestige}` : ''})` : 'لا يوجد'}\n\n` +
          `${activeBoss ? `🐉 **بوس نشط:** ${activeBoss.name} ❤️ ${activeBoss.hp.toLocaleString()}/${activeBoss.max_hp.toLocaleString()}` : '🐉 **لا يوجد بوس نشط**'}`,
          0x6a0dad
        );
        await interaction.reply({ embeds: [embed] });
        break;
      }
    }
  }
};

