arguments.content:
const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer, getPlayerGuild, getGuild, getGuildByName, getGuildMembers, runQuery, allQuery, getQuery } = require('../../database/db');
const { createBaseEmbed, createGuildEmbed } = require('../../utils/embeds');
const { randomInt, calculateGuildWar, formatNumber } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('guild')
    .setDescription('🏰 نظام القبائل - أنشئ أو انضم إلى قبيلة')
    .addSubcommand(sub =>
      sub.setName('create')
        .setDescription('إنشاء قبيلة جديدة')
        .addStringOption(option =>
          option.setName('name')
            .setDescription('اسم القبيلة')
            .setRequired(true)
            .setMinLength(3)
            .setMaxLength(30)
        )
        .addStringOption(option =>
          option.setName('description')
            .setDescription('وصف القبيلة')
            .setRequired(false)
            .setMaxLength(200)
        )
    )
    .addSubcommand(sub =>
      sub.setName('join')
        .setDescription('الانضمام إلى قبيلة')
        .addStringOption(option =>
          option.setName('guild_name')
            .setDescription('اسم القبيلة')
            .setRequired(true)
            .setAutocomplete(true)
        )
    )
    .addSubcommand(sub =>
      sub.setName('info')
        .setDescription('عرض معلومات قبيلتك')
    )
    .addSubcommand(sub =>
      sub.setName('list')
        .setDescription('عرض قائمة القبائل')
    )
    .addSubcommand(sub =>
      sub.setName('leave')
        .setDescription('مغادرة القبيلة الحالية')
    )
    .addSubcommand(sub =>
      sub.setName('war')
        .setDescription('⚔️ إعلان حرب على قبيلة أخرى')
        .addStringOption(option =>
          option.setName('target')
            .setDescription('اسم القبيلة المستهدفة')
            .setRequired(true)
            .setAutocomplete(true)
        )
    )
    .addSubcommand(sub =>
      sub.setName('upgrade')
        .setDescription('⬆️ تطوير القبيلة إلى المستوى التالي')
    )
    .addSubcommand(sub =>
      sub.setName('deposit')
        .setDescription('💰 إيداع ذهب في خزينة القبيلة')
        .addIntegerOption(option =>
          option.setName('amount')
            .setDescription('كمية الذهب')
            .setRequired(true)
            .setMinValue(1)
        )
    )
    .addSubcommand(sub =>
      sub.setName('members')
        .setDescription('👥 عرض أعضاء القبيلة')
    ),

  async execute(interaction) {
    const subcommand = interaction.options.getSubcommand();

    switch (subcommand) {
      case 'create':
        return handleCreate(interaction);
      case 'join':
        return handleJoin(interaction);
      case 'info':
        return handleInfo(interaction);
      case 'list':
        return handleList(interaction);
      case 'leave':
        return handleLeave(interaction);
      case 'members':
        return handleMembers(interaction);
      case 'war':
        return handleWar(interaction);
      case 'upgrade':
        return handleUpgrade(interaction);
      case 'deposit':
        return handleDeposit(interaction);
    }
  }
};

async function handleCreate(interaction) {
  const name = interaction.options.getString('name');
  const description = interaction.options.getString('description') || 'قبيلة من نسّاجي الظل';

  const player = getPlayer(interaction.user.id, interaction.user.username);

  const existingGuild = getPlayerGuild(interaction.user.id);
  if (existingGuild) {
    return interaction.reply({ content: `❌ أنت بالفعل في قبيلة **${existingGuild.name}**! اتركها أولاً باستخدام \`/guild leave\`.`, ephemeral: true });
  }

  const nameExists = getGuildByName(name);
  if (nameExists) {
    return interaction.reply({ content: '❌ هذا الاسم مستخدم بالفعل!', ephemeral: true });
  }

  if (player.gold < 5000) {
    return interaction.reply({ content: '❌ تحتاج 5000 ذهب لإنشاء قبيلة!', ephemeral: true });
  }

  updatePlayer(interaction.user.id, { gold: player.gold - 5000 });

  const result = runQuery('INSERT INTO guilds (name, owner_id, description) VALUES (?, ?, ?)', [name, interaction.user.id, description]);
  runQuery('INSERT INTO guild_members (guild_id, user_id, role) VALUES (?, ?, ?)', [result.lastInsertRowid, interaction.user.id, 'زعيم']);

  const embed = createBaseEmbed('🏰 تم إنشاء القبيلة!', 
    `تم إنشاء قبيلة **${name}** بنجاح!\n\n` +
    `👑 الزعيم: ${interaction.user.username}\n` +
    `📝 الوصف: ${description}\n` +
    `💰 التكلفة: 5000 ذهب\n\n` +
    `استخدم \`/guild info\` لعرض معلومات القبيلة.`,
    0x6a0dad
  );

  await interaction.reply({ embeds: [embed] });
}

async function handleJoin(interaction) {
  const guildName = interaction.options.getString('guild_name');
  const guild = getGuildByName(guildName);

  if (!guild) {
    return interaction.reply({ content: '❌ لا توجد قبيلة بهذا الاسم!', ephemeral: true });
  }

  const existingGuild = getPlayerGuild(interaction.user.id);
  if (existingGuild) {
    return interaction.reply({ content: `❌ أنت بالفعل في قبيلة **${existingGuild.name}**! اتركها أولاً.`, ephemeral: true });
  }

  const member = getQuery('SELECT * FROM guild_members WHERE guild_id = ? AND user_id = ?', [guild.id, interaction.user.id]);
  if (member) {
    return interaction.reply({ content: '❌ أنت بالفعل عضو في هذه القبيلة!', ephemeral: true });
  }

  runQuery('INSERT INTO guild_members (guild_id, user_id, role) VALUES (?, ?, ?)', [guild.id, interaction.user.id, 'عضو']);

  const embed = createBaseEmbed('✅ انضممت إلى القبيلة!',
    `مرحباً بك في **${guild.name}**!\n\n` +
    `👑 الزعيم: <@${guild.owner_id}>\n` +
    `📊 مستوى القبيلة: ${guild.level}\n` +
    `💰 الخزينة: ${guild.treasury?.toLocaleString() || 0} ذهب\n\n` +
    `ادعم قبيلتك باستخدام \`/guild deposit\``,
    0x00ff88
  );

  await interaction.reply({ embeds: [embed] });
}

async function handleInfo(interaction) {
  const guild = getPlayerGuild(interaction.user.id);

  if (!guild) {
    return interaction.reply({ content: '❌ أنت لست في أي قبيلة! استخدم `/guild create` أو `/guild join`.', ephemeral: true });
  }

  const members = getGuildMembers(guild.id);
  const embed = createGuildEmbed(guild, members);

  // Add extra info
  embed.addFields(
    { name: '💰 الخزينة', value: `${(guild.treasury || 0).toLocaleString()} ذهب`, inline: true },
    { name: '⚔️ الفوز/الخسارة', value: `${guild.wins || 0}ف / ${guild.losses || 0}خ`, inline: true },
    { name: '⬆️ تكلفة الترقية التالية', value: `${getUpgradeCost(guild.level).toLocaleString()} ذهب`, inline: true }
  );

  await interaction.reply({ embeds: [embed] });
}

async function handleMembers(interaction) {
  const guild = getPlayerGuild(interaction.user.id);
  if (!guild) {
    return interaction.reply({ content: '❌ أنت لست في أي قبيلة!', ephemeral: true });
  }

  const members = getGuildMembers(guild.id);

  const roleEmojis = { 'زعيم': '👑', 'نائب': '⚜️', 'عضو': '▪️' };
  const desc = members.map(m => 
    `${roleEmojis[m.role] || '▪️'} **${m.username}** — ${m.role}\n` +
    `   📊 مساهمة: ${(m.contribution || 0).toLocaleString()} | 📅 ${m.joined_at?.split('T')[0] || '?'}`
  ).join('\n');

  const embed = createBaseEmbed(`👥 أعضاء ${guild.name} (${members.length})`, desc, 0x6a0dad);
  await interaction.reply({ embeds: [embed] });
}

async function handleList(interaction) {
  const guilds = allQuery(
    'SELECT g.*, COUNT(gm.user_id) as member_count FROM guilds g LEFT JOIN guild_members gm ON g.id = gm.guild_id GROUP BY g.id ORDER BY g.level DESC, g.xp DESC LIMIT 20'
  );

  if (guilds.length === 0) {
    return interaction.reply({ content: '❌ لا توجد قبائل مسجلة بعد! كن أنت الأول باستخدام `/guild create`.', ephemeral: true });
  }

  const list = guilds.map((g, i) => 
    `**${i + 1}.** ${g.name} (المستوى ${g.level})\n` +
    `   👥 ${g.member_count} أعضاء | 👑 <@${g.owner_id}> | ⚔️ ${g.wins || 0}ف/${g.losses || 0}خ`
  ).join('\n\n');

  const embed = createBaseEmbed('🏰 قائمة القبائل', list, 0x6a0dad);
  await interaction.reply({ embeds: [embed] });
}

async function handleLeave(interaction) {
  const guild = getPlayerGuild(interaction.user.id);

  if (!guild) {
    return interaction.reply({ content: '❌ أنت لست في أي قبيلة!', ephemeral: true });
  }

  if (guild.owner_id === interaction.user.id) {
    return interaction.reply({ content: '❌ لا يمكنك مغادرة القبيلة وأنت الزعيم! قم بنقل الزعامة أولاً أو احذف القبيلة.', ephemeral: true });
  }

  runQuery('DELETE FROM guild_members WHERE guild_id = ? AND user_id = ?', [guild.id, interaction.user.id]);

  const embed = createBaseEmbed('👋 غادرت القبيلة', `لقد غادرت قبيلة **${guild.name}** بنجاح.`, 0x888888);
  await interaction.reply({ embeds: [embed] });
}

async function handleDeposit(interaction) {
  const amount = interaction.options.getInteger('amount');
  const player = getPlayer(interaction.user.id, interaction.user.username);
  const guild = getPlayerGuild(interaction.user.id);

  if (!guild) {
    return interaction.reply({ content: '❌ أنت لست في أي قبيلة!', ephemeral: true });
  }

  if (player.gold < amount) {
    return interaction.reply({ content: `❌ ليس لديك ${amount.toLocaleString()} ذهب!`, ephemeral: true });
  }

  updatePlayer(interaction.user.id, { gold: player.gold - amount });
  runQuery('UPDATE guilds SET treasury = COALESCE(treasury, 0) + ? WHERE id = ?', [amount, guild.id]);

  // Track contribution
  const member = getQuery('SELECT * FROM guild_members WHERE guild_id = ? AND user_id = ?', [guild.id, interaction.user.id]);
  if (member) {
    runQuery('UPDATE guild_members SET contribution = COALESCE(contribution, 0) + ? WHERE guild_id = ? AND user_id = ?', 
      [Math.floor(amount * 0.1), guild.id, interaction.user.id]);
  }

  // Add guild XP
  const guildXp = Math.floor(amount * 0.05);
  runQuery('UPDATE guilds SET xp = COALESCE(xp, 0) + ? WHERE id = ?', [guildXp, guild.id]);

  // Check level up
  const updatedGuild = getGuild(guild.id);
  if (updatedGuild.xp >= getUpgradeXpNeeded(updatedGuild.level)) {
    // Auto-level up
    runQuery('UPDATE guilds SET level = level + 1, xp = xp - ? WHERE id = ?', [getUpgradeXpNeeded(updatedGuild.level), guild.id]);
  }

  const embed = createBaseEmbed('💰 إيداع في الخزينة',
    `**${interaction.user.username}** أودع **${amount.toLocaleString()}** ذهب في خزينة **${guild.name}**!\n\n` +
    `💰 الخزينة الآن: ${(guild.treasury || 0) + amount} ذهب\n` +
    `📊 XP القبيلة: +${guildXp}`,
    0xffd700
  );

  await interaction.reply({ embeds: [embed] });
}

async function handleUpgrade(interaction) {
  const guild = getPlayerGuild(interaction.user.id);

  if (!guild) {
    return interaction.reply({ content: '❌ أنت لست في أي قبيلة!', ephemeral: true });
  }

  if (guild.owner_id !== interaction.user.id) {
    return interaction.reply({ content: '❌ فقط زعيم القبيلة يمكنه تطويرها!', ephemeral: true });
  }

  if (guild.level >= 20) {
    return interaction.reply({ content: '❌ القبيلة في أقصى مستوى لها! (المستوى 20)', ephemeral: true });
  }

  const cost = getUpgradeCost(guild.level);
  const members = getGuildMembers(guild.id);
  const memberCount = members.length;
  const requiredMembers = guild.level * 2;

  if (memberCount < requiredMembers) {
    return interaction.reply({ content: `❌ تحتاج ${requiredMembers} أعضاء على الأقل للترقية! لديك ${memberCount}.`, ephemeral: true });
  }

  if ((guild.treasury || 0) < cost) {
    return interaction.reply({ content: `❌ الخزينة تحتاج ${cost.toLocaleString()} ذهب للترقية! لديك ${(guild.treasury || 0).toLocaleString()}.`, ephemeral: true });
  }

  runQuery('UPDATE guilds SET treasury = treasury - ?, level = level + 1, xp = 0 WHERE id = ?', [cost, guild.id]);

  const embed = createBaseEmbed('⬆️ **ترقية القبيلة!**',
    `**${guild.name}** → **المستوى ${guild.level + 1}** 🎉\n\n` +
    `💰 التكلفة: ${cost.toLocaleString()} ذهب\n` +
    `📊 الفوائد:\n` +
    `• سعة أعضاء: +${guild.level + 2}\n` +
    `• قوة القبيلة: +${guild.level * 5}\n` +
    `• XP مكافأة: ×${1 + guild.level * 0.1}`,
    0xffd700
  );

  await interaction.reply({ embeds: [embed] });
}

async function handleWar(interaction) {
  const targetName = interaction.options.getString('target');
  const attackerGuild = getPlayerGuild(interaction.user.id);

  if (!attackerGuild) {
    return interaction.reply({ content: '❌ يجب أن تكون في قبيلة لإعلان الحرب!', ephemeral: true });
  }

  if (attackerGuild.owner_id !== interaction.user.id) {
    return interaction.reply({ content: '❌ فقط الزعيم يمكنه إعلان الحرب!', ephemeral: true });
  }

  const defenderGuild = getGuildByName(targetName);
  if (!defenderGuild) {
    return interaction.reply({ content: '❌ لا توجد قبيلة بهذا الاسم!', ephemeral: true });
  }

  if (defenderGuild.id === attackerGuild.id) {
    return interaction.reply({ content: '❌ لا يمكنك إعلان الحرب على قبيلتك!', ephemeral: true });
  }

  if (attackerGuild.level < 3) {
    return interaction.reply({ content: '❌ تحتاج قبيلة من المستوى 3+ لإعلان الحرب!', ephemeral: true });
  }

  const cost = 2000 + attackerGuild.level * 500;
  if ((attackerGuild.treasury || 0) < cost) {
    return interaction.reply({ content: `❌ الخزينة تحتاج ${cost.toLocaleString()} ذهب للحرب!`, ephemeral: true });
  }

  // Deduct war cost
  runQuery('UPDATE guilds SET treasury = treasury - ? WHERE id = ?', [cost, attackerGuild.id]);

  // Calculate war result
  const result = calculateGuildWar(attackerGuild.id, defenderGuild.id);

  const winnerId = result.attackerWins ? attackerGuild.id : defenderGuild.id;
  const winnerName = result.attackerWins ? attackerGuild.name : defenderGuild.name;
  const loserName = result.attackerWins ? defenderGuild.name : attackerGuild.name;

  // Update win/loss records
  runQuery('UPDATE guilds SET wins = COALESCE(wins, 0) + ?, xp = COALESCE(xp, 0) + ? WHERE id = ?', 
    [result.attackerWins ? 1 : 0, result.xpReward, attackerGuild.id]);
  runQuery('UPDATE guilds SET losses = COALESCE(losses, 0) + 1 WHERE id = ?', [defenderGuild.id]);

  // Winner gets gold from loser's treasury
  const stolenGold = Math.min(defenderGuild.treasury || 0, Math.floor(result.goldReward * 2));
  if (stolenGold > 0) {
    runQuery('UPDATE guilds SET treasury = treasury - ? WHERE id = ?', [stolenGold, defenderGuild.id]);
    runQuery('UPDATE guilds SET treasury = COALESCE(treasury, 0) + ? WHERE id = ?', [stolenGold, attackerGuild.id]);
  }

  const embed = createBaseEmbed('⚔️ **حرب القبائل!**',
    `**${attackerGuild.name}** ⚔️ **${defenderGuild.name}**\n\n` +
